      const sumByPattern = (prefixes: string[], keywords: string[]) => {
          return accounts
              .filter(a => {
                  const nameMatch = keywords.some(k => a.account_name.toLowerCase().includes(k.toLowerCase()));
                  const codeMatch = prefixes.some(p => a.account_code?.startsWith(p));
                  // We prioritize analytical sums or top-level group totals if codes are consistent
                  return (codeMatch || nameMatch) && a.level <= 3;
              })
              .reduce((sum, a) => {
                  // If it's a synthetic account, we only take it if it matches the group exactly to avoid double counting
                  // But often accounts don't have levels, so we take analytical if possible.
                  if (a.is_synthetic) return sum + a.final_balance;
                  return sum; // simplified logic for demo: trust synthetic totals if provided
              }, 0);
      };

      // Extract based on common Brazilian Plan of Accounts (1=Active, 2=Passive)
      const ac = Math.abs(accounts.find(a => a.account_code === '1.1' || a.account_name.toLowerCase().includes('ativo circulante'))?.final_balance || 0);
      const anc = Math.abs(accounts.find(a => a.account_code === '1.2' || a.account_name.toLowerCase().includes('ativo não circulante'))?.final_balance || 0);
      const pc = Math.abs(accounts.find(a => a.account_code === '2.1' || a.account_name.toLowerCase().includes('passivo circulante'))?.final_balance || 0);
      const pnc = Math.abs(accounts.find(a => a.account_code === '2.2' || a.account_name.toLowerCase().includes('passivo não circulante'))?.final_balance || 0);
      const pl = Math.abs(accounts.find(a => a.account_code === '2.3' || a.account_name.toLowerCase().includes('patrimônio líquido'))?.final_balance || 0);

      const hasData = (ac + anc + pc + pnc + pl) > 0;
      if (!hasData) return null;

      return [
          {
              name: 'Ativo',
              Circulante: ac,
              NaoCirculante: anc,
          },
          {
              name: 'Passivo + PL',
              Circulante: pc,
              NaoCirculante: pnc,
              PatrimonioLiquido: pl
          }
      ];
  }, [accounts]);

  const baseChartData = useMemo(() => {
      if (!accounts || accounts.length === 0) return [];
      let validAccounts = accounts.filter(a => !a.is_synthetic && (a.initial_balance !== 0 || a.final_balance !== 0));
      const topAccounts = validAccounts
          .sort((a, b) => Math.abs(b.final_balance) - Math.abs(a.final_balance))
          .slice(0, 10); 
      return topAccounts.map(acc => ({
          id: acc.account_code ? `${acc.account_code}-${acc.account_name}` : acc.account_name, 
          name: acc.account_name.length > 25 ? acc.account_name.substring(0, 25) + '...' : acc.account_name,
          initial: acc.initial_balance,
          final: acc.final_balance
      }));
  }, [accounts]);

  useEffect(() => {
      if (baseChartData.length > 0) {
          const currentSig = baseChartData.map(d => d.id).join('|');
          if (currentSig !== chartDataSignature) {
              setSelectedChartAccounts(baseChartData.slice(0, 5).map(d => d.id));
              setChartDataSignature(currentSig);
          }
      }
  }, [baseChartData, chartDataSignature]);

  const activeChartData = useMemo(() => baseChartData.filter(d => selectedChartAccounts.includes(d.id)), [baseChartData, selectedChartAccounts]);

  const finalResultValue = summary?.specific_result_value || 0;
  const finalResultLabel = summary?.specific_result_label || (finalResultValue >= 0 ? 'LUCRO' : 'PREJUÍZO');

  const profitLossStyle = finalResultValue >= 0 
      ? { text: 'text-blue-700 dark:text-blue-300', bg: 'bg-blue-50 dark:bg-blue-900/20', border: 'border-blue-200 dark:border-blue-800' }
      : { text: 'text-red-700 dark:text-red-300', bg: 'bg-red-50 dark:bg-red-900/20', border: 'border-red-200 dark:border-red-800' };

  const getDisplayedName = (account: ExtractedAccount) => {
      let correctedName = account.account_name;
      spell_check.forEach(sc => {
          if (sc.confidence !== 'Low') {
              const escapedOriginal = sc.original_term.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
              const regex = new RegExp(escapedOriginal, 'gi');
              correctedName = correctedName.replace(regex, sc.suggested_correction);
          }
      });
      return correctedName;
  };

  const getSuggestionForAccount = (account: ExtractedAccount) => {
      const corrected = getDisplayedName(account);
      return corrected !== account.account_name ? corrected : null;
  };

  const filteredAndSortedAccounts = useMemo(() => {
    if (!accounts) return [];
    let processedAccounts = accounts.map((acc, index) => ({ ...acc, originalIndex: index }));

    if (searchTerm) {
        const s = searchTerm.toLowerCase();
        processedAccounts = processedAccounts.filter(a => a.account_name.toLowerCase().includes(s) || (a.account_code && a.account_code.toLowerCase().includes(s)));
    }
    if (filterType !== 'All') processedAccounts = processedAccounts.filter(acc => acc.type === filterType);
    if (filterInversion === 'yes') processedAccounts = processedAccounts.filter(acc => acc.possible_inversion && !acc.is_synthetic);
    if (filterInversion === 'no') processedAccounts = processedAccounts.filter(acc => !acc.possible_inversion);
    if (filterHasCorrection) processedAccounts = processedAccounts.filter(acc => getSuggestionForAccount(acc) !== null);

    if (sortConfig) {
      processedAccounts.sort((a, b) => {
        let aVal: any = a[sortConfig.key] || '', bVal: any = b[sortConfig.key] || '';
        return aVal < bVal ? (sortConfig.direction === 'asc' ? -1 : 1) : (sortConfig.direction === 'asc' ? 1 : -1);
      });
    }
    return processedAccounts;
  }, [accounts, sortConfig, searchTerm, filterType, filterInversion, filterHasCorrection, expandedGroups, showCorrectedNames]);

  const paginatedAccounts = filteredAndSortedAccounts.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  const handleGoogleSearch = (code: string, name: string) => {
      const query = encodeURIComponent(`${code} ${name} contabilidade brasil`);
      window.open(`https://www.google.com/search?q=${query}`, '_blank');
  };

  return (
    <div className="space-y-8 animate-fadeIn relative">
      <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm mb-2 border border-slate-200 dark:border-slate-700 print:hidden">
        <h2 className="text-2xl font-bold text-slate-800 dark:text-white flex items-center justify-between">
            {headerData.companyName || 'Empresa não identificada'}
            <span className="text-sm font-mono bg-blue-100 text-blue-700 px-3 py-1 rounded-full">{summary.period}</span>
        </h2>
      </div>

      <div id="summary" className="bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 overflow-hidden">
        <div className="bg-slate-800 px-6 py-4 flex justify-between items-center">
          <h3 className="text-xl font-semibold text-white">Resumo: {summary.document_type}</h3>
          <button onClick={() => window.print()} className="text-xs bg-slate-700 text-white px-4 py-2 rounded-full border border-slate-600 font-bold">Imprimir Relatório</button>
        </div>

        <div className="p-6 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <div className="p-4 bg-blue-50 dark:bg-blue-900/20 rounded-lg border border-blue-100">
                <p className="text-xs text-blue-600 font-bold uppercase">Débitos</p>
                <p className="text-2xl font-bold text-blue-900 dark:text-blue-100 mt-1">{formatCurrency(summary.total_debits)}</p>
            </div>
            <div className="p-4 bg-red-50 dark:bg-red-900/20 rounded-lg border border-red-100">
                <p className="text-xs text-red-600 font-bold uppercase">Créditos</p>
                <p className="text-2xl font-bold text-red-900 dark:text-red-100 mt-1">{formatCurrency(summary.total_credits)}</p>
            </div>
            <div className={`p-4 rounded-lg border ${profitLossStyle.bg} ${profitLossStyle.border}`}>
                <p className={`text-xs font-bold uppercase ${profitLossStyle.text}`}>{finalResultLabel}</p>
                <p className={`text-2xl font-bold mt-1 ${profitLossStyle.text}`}>{formatCurrency(finalResultValue)}</p>
            </div>
            <div className={`p-4 rounded-lg border ${summary.is_balanced ? 'bg-emerald-50' : 'bg-rose-50'}`}>
                <p className="text-xs text-slate-500 font-bold uppercase">Conformidade</p>
                <span className={`text-lg font-bold ${summary.is_balanced ? 'text-emerald-700' : 'text-rose-700'}`}>
                    {summary.is_balanced ? 'Balanceado ✅' : `Divergente (${formatCurrency(summary.discrepancy_amount)}) ⚠️`}
                </span>
            </div>
        </div>
      </div>

       {balanceSheetChartData ? (
          <div className="bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 overflow-hidden mb-6">
             <div className="px-6 py-4 bg-indigo-50 dark:bg-indigo-900/30 border-b border-indigo-100">
                 <h3 className="text-lg font-bold text-indigo-900 dark:text-indigo-100 flex items-center gap-2">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path d="M2 11a1 1 0 011-1h2a1 1 0 011 1v5a1 1 0 01-1 1H3a1 1 0 01-1-1v-5zM8 7a1 1 0 011-1h2a1 1 0 011 1v9a1 1 0 01-1 1H9a1 1 0 01-1-1V7zM14 4a1 1 0 011-1h2a1 1 0 011 1v12a1 1 0 01-1 1h-2a1 1 0 01-1-1V4z" /></svg>
                    Estrutura Patrimonial (Análise de Grupos)
                 </h3>
             </div>
             <div className="p-6 w-full h-[350px]">
                 <ResponsiveContainer width="100%" height="100%">
                     <BarChart data={balanceSheetChartData} layout="vertical" barSize={40} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
                         <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#e2e8f0" />
                         <XAxis type="number" tickFormatter={(v) => new Intl.NumberFormat('pt-BR', { notation: 'compact' }).format(v)} />
                         <YAxis dataKey="name" type="category" width={100} />
                         <Tooltip formatter={(value: number) => formatCurrency(value)} />
                         <Legend />
                         <Bar dataKey="Circulante" stackId="a" fill="#3b82f6" name="Circulante" />
                         <Bar dataKey="NaoCirculante" stackId="a" fill="#1d4ed8" name="Não Circulante" />
                         <Bar dataKey="PatrimonioLiquido" stackId="a" fill="#10b981" name="Patrimônio Líquido" />
                     </BarChart>
                 </ResponsiveContainer>
             </div>
          </div>
       ) : (
           <div className="p-10 bg-white dark:bg-slate-800 rounded-xl border border-dashed text-center text-slate-400">
               Nenhum dado de estrutura patrimonial (Ativo/Passivo) identificado para o gráfico. Verifique se as contas estão codificadas.
           </div>
       )}

      <div id="accounts" className="bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 overflow-hidden">
         <div className="px-6 py-4 border-b dark:border-slate-700 flex flex-wrap justify-between items-center gap-3">
            <h3 className="text-lg font-semibold dark:text-white flex items-center gap-2">
                Detalhamento Analítico ({filteredAndSortedAccounts.length})
                <button onClick={() => setShowThemeSettings(!showThemeSettings)} className="text-xs bg-slate-100 dark:bg-slate-700 px-3 py-1.5 rounded-full border">Tema Tabela</button>
            </h3>

            <div className="flex flex-wrap gap-2 items-center">
                <div className="flex bg-slate-100 dark:bg-slate-700 rounded p-1 border">
                    <button onClick={() => setFilterInversion('all')} className={`px-3 py-1 text-xs rounded ${filterInversion === 'all' ? 'bg-white shadow-sm font-bold' : 'text-slate-500'}`}>Todas</button>
                    <button onClick={() => setFilterInversion('yes')} className={`px-3 py-1 text-xs rounded ${filterInversion === 'yes' ? 'bg-red-500 text-white font-bold' : 'text-slate-500'}`}>Invertidas</button>
                </div>
                <button onClick={() => setShowCorrectedNames(!showCorrectedNames)} className="px-3 py-1.5 rounded text-xs border bg-white dark:bg-slate-700 dark:text-white">
                    {showCorrectedNames ? 'Exibir Originais' : 'Exibir Corrigidos'}
                </button>
                <button onClick={() => setShowSuggestionCol(!showSuggestionCol)} className="px-3 py-1.5 rounded text-xs border bg-white dark:bg-slate-700 dark:text-white">Sugestões Ortográficas</button>
            </div>
         </div>

         <div style={{'--theme-header-bg': customTheme.headerBg, '--theme-header-text': customTheme.headerText, '--theme-row-odd': customTheme.rowOddBg, '--theme-row-even': customTheme.rowEvenBg, '--theme-border': customTheme.border} as React.CSSProperties} className="overflow-auto max-h-[70vh]">
          <table className="min-w-full divide-y divide-[var(--theme-border)]">
            <thead className="bg-[var(--theme-header-bg)] sticky top-0 z-20">
              <tr>
                <th style={{ color: 'var(--theme-header-text)' }} className="px-4 py-3 text-left text-xs font-medium uppercase">Código</th>
                <th style={{ color: 'var(--theme-header-text)' }} className="px-4 py-3 text-left text-xs font-medium uppercase">Conta</th>
                <th style={{ color: 'var(--theme-header-text)' }} className="px-4 py-3 text-center text-xs font-medium uppercase">Tipo</th>
                {showSuggestionCol && <th className="px-4 py-3 text-left text-xs font-medium text-blue-600 uppercase">Sugestão Ortográfica</th>}
                <th style={{ color: 'var(--theme-header-text)' }} className="px-4 py-3 text-right text-xs font-medium uppercase">Sdo. Anterior</th>
                <th style={{ color: 'var(--theme-header-text)' }} className="px-4 py-3 text-right text-xs font-medium uppercase">Sdo. Atual</th>
                <th style={{ color: 'var(--theme-header-text)' }} className="px-4 py-3 text-center text-xs font-medium uppercase">Validar</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-[var(--theme-border)]">
                  {paginatedAccounts.map((account, index) => {
                        const isOdd = index % 2 !== 0;
                        const rowStyle = { backgroundColor: isOdd ? 'var(--theme-row-odd)' : 'var(--theme-row-even)' };
                        const hasCorrection = getSuggestionForAccount(account) !== null;

                        return (
                        <tr key={account.originalIndex} style={rowStyle} className={`hover:opacity-90 transition-colors ${account.is_synthetic ? 'font-bold' : ''}`}>
                          <td className="px-4 py-3 text-sm font-mono text-blue-600">{account.account_code || '-'}</td>
                          <td className="px-4 py-3 text-sm dark:text-slate-800">
                            <div className="flex items-center gap-2">
                                {showCorrectedNames ? getDisplayedName(account) : account.account_name}
                                {hasCorrection && showCorrectedNames && <span className="text-[10px] bg-green-100 text-green-700 px-1 rounded border border-green-200">Corrigido</span>}
                            </div>
                          </td>
                          <td className="px-4 py-3 text-center text-xs font-bold">
                              <span className={`px-2 py-0.5 rounded-full border ${account.type === 'Debit' ? 'bg-blue-100 text-blue-800' : 'bg-red-100 text-red-800'}`}>{account.type === 'Debit' ? 'D' : 'C'}</span>
                          </td>
                          {showSuggestionCol && (
                              <td className="px-4 py-3 text-sm italic">
                                {hasCorrection ? (
                                    <div className="text-blue-600 font-medium">{getSuggestionForAccount(account)}</div>
                                ) : <span className="text-slate-300">-</span>}
                              </td>
                          )}
                          <td className="px-4 py-3 text-right text-sm font-mono text-slate-500">{formatCurrency(account.initial_balance)}</td>
                          <td className="px-4 py-3 text-right text-sm font-mono text-slate-800">{formatCurrency(account.final_balance)}</td>
                          <td className="px-4 py-3 text-center">
                             <button 
                                onClick={() => handleGoogleSearch(account.account_code || '', account.account_name)}
                                title="Validar conta no Google"
                                className="text-slate-400 hover:text-blue-600 transition-colors"
                             >
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" /></svg>
                             </button>
                          </td>
                        </tr>
                  )})}
            </tbody>
          </table>
         </div>
      </div>
    </div>
  );
};

export default AnalysisViewer;

import React, { useState, useMemo, useEffect } from 'react';
import { HistoryItem } from '../types';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  history: HistoryItem[];
  onSelect: (item: HistoryItem) => void;
  onClear: () => void;
  onDeleteItem?: (id: string) => void;
  onCompare?: (item1: HistoryItem, item2: HistoryItem) => void;
  currentUser?: string;
}

const ITEMS_PER_PAGE = 8;

const HistoryListItem = React.memo(({ 
    item, 
    isSelected, 
    isCompareMode, 
    onClick,
    onDelete 
