import React, { useState, useEffect, useMemo } from 'react';
import HeaderInputs from './components/HeaderInputs';
import FileUploader from './components/FileUploader';
import AnalysisViewer from './components/AnalysisViewer';
import AnalysisHistory from './components/AnalysisHistory';
import ChatAssistant from './components/ChatAssistant';
import ComparisonViewer from './components/ComparisonViewer';
import { HeaderData, AnalysisResult, HistoryItem, ComparisonResult, ComparisonRow } from './types';
import { analyzeDocument } from './services/geminiService';

const HISTORY_STORAGE_KEY = 'auditAI_history';
const CACHE_STORAGE_PREFIX = 'auditAI_cache_';
const THEME_STORAGE_KEY = 'auditAI_theme';
const MAX_HISTORY_ITEMS = 100;

const LoadingSpinner = () => (
  <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex flex-col items-center justify-center z-50 animate-fadeIn">
     <div className="bg-white dark:bg-slate-800 p-8 rounded-2xl shadow-2xl flex flex-col items-center">
        <div className="relative flex items-center justify-center mb-6">
           <div className="animate-ping absolute inline-flex h-12 w-12 rounded-full bg-blue-500/20 opacity-75"></div>
           <div className="relative animate-spin rounded-full h-16 w-16 border-t-4 border-blue-500"></div>
        </div>
        <h3 className="text-xl font-bold text-slate-800 dark:text-white mb-2">Analisando Documento...</h3>
        <p className="text-blue-500 font-medium animate-pulse">A IA está extraindo e validando os dados.</p>
     </div>
  </div>
);

const App: React.FC = () => {
  const [headerData, setHeaderData] = useState<HeaderData>({ companyName: '', collaboratorName: '', cnpj: '' });
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [selectedFile, setSelectedFile] = useState<{file: File, base64: string, mimeType: string} | null>(null);
  const [analysisTimestamp, setAnalysisTimestamp] = useState<string | null>(null);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [darkMode, setDarkMode] = useState(false);
  const [comparisonResult, setComparisonResult] = useState<ComparisonResult | null>(null);

  useEffect(() => {
    const savedHistory = localStorage.getItem(HISTORY_STORAGE_KEY);
    if (savedHistory) {
        try {
            setHistory(JSON.parse(savedHistory));
        } catch (e) {
            console.error("Failed to load history", e);
        }
    }
    const savedTheme = localStorage.getItem(THEME_STORAGE_KEY);
    if (savedTheme === 'dark' || (!savedTheme && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
        setDarkMode(true);
        document.documentElement.classList.add('dark');
    }
  }, []);

  const toggleTheme = () => {
    const newMode = !darkMode;
    setDarkMode(newMode);
    if (newMode) { document.documentElement.classList.add('dark'); localStorage.setItem(THEME_STORAGE_KEY, 'dark'); }
    else { document.documentElement.classList.remove('dark'); localStorage.setItem(THEME_STORAGE_KEY, 'light'); }
  };

  const getFullResult = (item: HistoryItem): AnalysisResult | null => {
      let fullResult = item.fullResult;
      if (!fullResult) {
          try {
            const cached = localStorage.getItem(`${CACHE_STORAGE_PREFIX}${item.id}`);
            if (cached) fullResult = JSON.parse(cached);
          } catch (e) {
            console.warn("Failed to retrieve cached result", e);
          }
      }
      return fullResult || null;
  };

  const saveToHistory = (result: AnalysisResult, header: HeaderData, fileName: string) => {
    const id = Date.now().toString();
    try { 
        localStorage.setItem(`${CACHE_STORAGE_PREFIX}${id}`, JSON.stringify(result)); 
    } catch (e) { 
        console.warn("Cache full, could not save detailed result", e); 
    }

    const newItem: HistoryItem = { 
        id, 
        timestamp: new Date().toISOString(), 
        headerData: { ...header }, 
        fileName, 
        summary: result.summary 
    };

    setHistory(prevHistory => {
        const updated = [newItem, ...prevHistory].slice(0, MAX_HISTORY_ITEMS);
        try {
            localStorage.setItem(HISTORY_STORAGE_KEY, JSON.stringify(updated));
        } catch (e) {
            console.error("Failed to save history list", e);
        }
        return updated;
    });
  };

  const deleteFromHistory = (id: string) => {
      setHistory(prev => {
          const updated = prev.filter(item => item.id !== id);
          localStorage.setItem(HISTORY_STORAGE_KEY, JSON.stringify(updated));
          localStorage.removeItem(`${CACHE_STORAGE_PREFIX}${id}`);
          return updated;
      });
  };

  const clearAllHistory = () => {
      history.forEach(item => localStorage.removeItem(`${CACHE_STORAGE_PREFIX}${item.id}`));
      setHistory([]);
      localStorage.removeItem(HISTORY_STORAGE_KEY);
  };

  const loadFromHistory = (item: HistoryItem) => {
      const fullResult = getFullResult(item);
      if (fullResult) {
          setHeaderData(item.headerData);
          setAnalysisResult(fullResult);
          setAnalysisTimestamp(item.timestamp);
          setSelectedFile({ file: { name: item.fileName } as File, base64: '', mimeType: '' });
          setError(null);
          setComparisonResult(null); 
          setIsHistoryOpen(false);
      } else { alert("Detalhes não encontrados no cache."); }
  };

  const handleComparison = (item1: HistoryItem, item2: HistoryItem) => {
      const res1 = getFullResult(item1);
      const res2 = getFullResult(item2);

      if (!res1 || !res2) {
          alert("Erro: Dados completos não encontrados para comparação.");
          return;
      }

      const rows: ComparisonRow[] = [];
      const map1 = new Map(res1.accounts.map(a => [a.account_code || a.account_name, a]));
      const map2 = new Map(res2.accounts.map(a => [a.account_code || a.account_name, a]));
      const allKeys = new Set([...map1.keys(), ...map2.keys()]);

      allKeys.forEach(key => {
          const acc1 = map1.get(key);
          const acc2 = map2.get(key);
          const name = acc2?.account_name || acc1?.account_name || 'Desconhecido';
          const code = acc2?.account_code || acc1?.account_code || '';
          const val1 = acc1 ? acc1.final_balance : 0;
          const val2 = acc2 ? acc2.final_balance : 0;
          const varAbs = val2 - val1;
          const varPct = val1 !== 0 ? (varAbs / Math.abs(val1)) * 100 : (val2 !== 0 ? 100 : 0);

          rows.push({
              code, name, val1, val2, varAbs, varPct,
              is_synthetic: (acc1?.is_synthetic || acc2?.is_synthetic) || false,
              level: acc1?.level || acc2?.level || 1
          });
      });

      rows.sort((a, b) => a.code.localeCompare(b.code, undefined, {numeric: true}));

      setComparisonResult({
          period1Label: new Date(item1.timestamp).toLocaleDateString('pt-BR'),
          period2Label: new Date(item2.timestamp).toLocaleDateString('pt-BR'),
          rows,
          documentType: item1.summary.document_type
      });
      setAnalysisResult(null);
      setIsHistoryOpen(false);
  };

  const handleStartAnalysis = async () => {
    if (!headerData.companyName || !headerData.collaboratorName) { setError("Preencha os dados da empresa e responsável."); return; }
    if (!selectedFile?.base64) { setError("Selecione um arquivo."); return; }
    setIsLoading(true); setError(null);
    try {
      const mime = selectedFile.mimeType || selectedFile.file.type;
      const result = await analyzeDocument(selectedFile.base64, mime);
      saveToHistory(result, headerData, selectedFile.file.name);
      setAnalysisTimestamp(new Date().toISOString());
      setAnalysisResult(result);
      setComparisonResult(null);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Erro desconhecido na análise.");
    } finally { setIsLoading(false); }
  };

  const handleReset = () => { 
      setAnalysisResult(null); 
      setComparisonResult(null); 
      setSelectedFile(null); 
      setError(null); 
  };

  const previousAccounts = useMemo(() => {
    if (!analysisResult || !headerData.companyName) return undefined;
    const currentTs = analysisTimestamp ? new Date(analysisTimestamp).getTime() : Date.now();
    const previousItem = history.find(h => {
        const itemTs = new Date(h.timestamp).getTime();
        return itemTs < (currentTs - 1000) && 
               h.headerData.companyName.toLowerCase() === headerData.companyName.toLowerCase() &&
               h.summary.document_type === analysisResult.summary.document_type;
    });
    if (previousItem) {
        const full = getFullResult(previousItem);
        return full?.accounts;
    }
    return undefined;
  }, [analysisResult, history, headerData.companyName, analysisTimestamp]);

  const isReady = !isLoading && selectedFile !== null && selectedFile.base64.length > 0;

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 pb-12 transition-colors duration-300">
      <AnalysisHistory 
        isOpen={isHistoryOpen} 
        onClose={() => setIsHistoryOpen(false)} 
        history={history} 
        onSelect={loadFromHistory} 
        onClear={clearAllHistory}
        onDeleteItem={deleteFromHistory}
        onCompare={handleComparison}
        currentUser={headerData.collaboratorName} 
      />

      <header className="bg-white dark:bg-slate-900 border-b dark:border-slate-800 py-4 sticky top-0 z-40">
         <div className="max-w-6xl mx-auto px-4 flex justify-between items-center">
            <div className="flex items-center gap-3">
                <div className="bg-blue-600 p-2 rounded-xl shadow-lg shadow-blue-500/20">
                    <svg className="w-6 h-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                </div>
                <div>
                    <h1 className="text-xl font-black text-slate-800 dark:text-white tracking-tight">Audit<span className="text-blue-600">AI</span></h1>
                    <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest leading-none">Smart Auditing System</p>
                </div>
            </div>
            <div className="flex items-center gap-2">
                <button onClick={toggleTheme} className="p-2.5 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-xl transition-all text-slate-500">{darkMode ? '☀' : '🌙'}</button>
                <button onClick={() => setIsHistoryOpen(true)} className="flex items-center gap-2 px-4 py-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-xl transition-all text-sm font-bold text-slate-600 dark:text-slate-300">
                    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                    Histórico
                </button>
                {(analysisResult || comparisonResult) && (
                    <button onClick={handleReset} className="bg-blue-600 text-white px-5 py-2 rounded-xl text-sm font-bold hover:bg-blue-700 shadow-lg shadow-blue-500/20 active:scale-95 transition-all">Nova Análise</button>
                )}
            </div>
         </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-8">
        {isLoading && <LoadingSpinner />}

        {!analysisResult && !comparisonResult && (
           <div className={isLoading ? 'opacity-50 blur-sm pointer-events-none' : 'space-y-6'}>
              <HeaderInputs data={headerData} onChange={setHeaderData} disabled={isLoading} />
              <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl shadow-sm border border-slate-200 dark:border-slate-800">
                  <div className="mb-6">
                    <h2 className="text-2xl font-black text-slate-800 dark:text-white mb-1">Upload de Dados</h2>
                    <p className="text-sm text-slate-500">Arraste seus relatórios financeiros para iniciar o processamento inteligente.</p>
                  </div>
                  <FileUploader 
                    onFileSelected={(f, b, m) => { setSelectedFile({file: f, base64: b, mimeType: m || f.type}); setError(null); }} 
                    isLoading={isLoading} 
                    selectedFileName={selectedFile?.file.name} 
                  />
                  {error && <div className="p-4 bg-red-50 dark:bg-red-900/10 text-red-700 dark:text-red-400 border border-red-100 dark:border-red-900/30 rounded-2xl mb-6 flex items-center gap-3 font-medium text-sm">
                      <svg className="w-5 h-5 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                      {error}
                  </div>}

                  <button 
                    onClick={handleStartAnalysis} 
                    disabled={!isReady}
                    className={`w-full py-5 rounded-2xl font-black text-lg shadow-xl transition-all
                        ${isReady 
                            ? 'bg-blue-600 hover:bg-blue-700 text-white transform hover:scale-[1.01] shadow-blue-500/25 active:scale-95' 
                            : 'bg-slate-100 dark:bg-slate-800 text-slate-400 cursor-not-allowed'}`}
                  >
                     {isLoading ? 'Analisando Estrutura...' : isReady ? '🚀 Processar com Inteligência Artificial' : 'Carregue um arquivo para começar'}
                  </button>
              </div>
           </div>
        )}

        {analysisResult && !isLoading && !comparisonResult && (
            <div className="animate-fadeIn">
                <AnalysisViewer 
                    result={analysisResult} 
                    headerData={headerData} 
                    previousAccounts={previousAccounts}
                />
            </div>
        )}

        {comparisonResult && !isLoading && (
            <div className="animate-fadeIn">
                <ComparisonViewer data={comparisonResult} onBack={() => { setComparisonResult(null); }} />
            </div>
        )}
      </main>

      <ChatAssistant />
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { AnalysisResult, ExtractedAccount, HeaderData } from '../types';
import { generateFinancialInsight, generateCMVAnalysis, generateSpedComplianceCheck } from '../services/geminiService';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';

interface Props {
  result: AnalysisResult;
  headerData: HeaderData;
  previousAccounts?: ExtractedAccount[];
}

type SortKey = keyof ExtractedAccount;

interface TableTheme {
    name: string;
    headerBg: string;
    headerText: string;
    rowOddBg: string;
    rowEvenBg: string;
    border: string;
}

const DEFAULT_THEMES: TableTheme[] = [
    { name: 'Padrão (Slate)', headerBg: '#f1f5f9', headerText: '#64748b', rowOddBg: '#ffffff', rowEvenBg: '#f8fafc', border: '#e2e8f0' },
    { name: 'Ocean (Azul)', headerBg: '#e0f2fe', headerText: '#0369a1', rowOddBg: '#ffffff', rowEvenBg: '#f0f9ff', border: '#bae6fd' },
];

const AnalysisViewer: React.FC<Props> = ({ result, headerData, previousAccounts }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [customTheme, setCustomTheme] = useState<TableTheme>(DEFAULT_THEMES[0]);
  const [activeTab, setActiveTab] = useState<'financial' | 'costs' | 'compliance'>('financial');

  // AI Opinions State
  const [opinions, setOpinions] = useState({
      financial: '',
      costs: '',
      compliance: ''
  });
  const [loadingOpinions, setLoadingOpinions] = useState({
      financial: false,
      costs: false,
      compliance: false
  });

  const formatCurrency = (value: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(value);

  const { summary, accounts = [], spell_check = [] } = result || {};

  // Funções para gerar os pareceres
  const fetchFinancialOpinion = async () => {
      if (opinions.financial || loadingOpinions.financial) return;
      setLoadingOpinions(prev => ({ ...prev, financial: true }));
      try {
          const res = await generateFinancialInsight(result, "Realize um parecer completo sobre a saúde financeira, liquidez e rentabilidade desta empresa.", 5);
          setOpinions(prev => ({ ...prev, financial: res }));
      } catch (e) { console.error(e); }
      finally { setLoadingOpinions(prev => ({ ...prev, financial: false })); }
  };

  const fetchCostsOpinion = async () => {
      if (opinions.costs || loadingOpinions.costs) return;
      setLoadingOpinions(prev => ({ ...prev, costs: true }));
      try {
          const res = await generateCMVAnalysis(result, "IFRS 18");
          setOpinions(prev => ({ ...prev, costs: res }));
      } catch (e) { console.error(e); }
      finally { setLoadingOpinions(prev => ({ ...prev, costs: false })); }
  };

  const fetchComplianceOpinion = async () => {
      if (opinions.compliance || loadingOpinions.compliance) return;
      setLoadingOpinions(prev => ({ ...prev, compliance: true }));
      try {
          const res = await generateSpedComplianceCheck(result);
          setOpinions(prev => ({ ...prev, compliance: res }));
      } catch (e) { console.error(e); }
      finally { setLoadingOpinions(prev => ({ ...prev, compliance: false })); }
  };

  // Carregar parecer inicial automaticamente
  useEffect(() => {
      fetchFinancialOpinion();
  }, [result]);

  const balanceSheetChartData = useMemo(() => {
      if (!accounts || accounts.length === 0) return null;
      const ac = Math.abs(accounts.find(a => a.account_code === '1.1' || a.account_name.toLowerCase().includes('ativo circulante'))?.final_balance || 0);
      const anc = Math.abs(accounts.find(a => a.account_code === '1.2' || a.account_name.toLowerCase().includes('ativo não circulante'))?.final_balance || 0);
      const pc = Math.abs(accounts.find(a => a.account_code === '2.1' || a.account_name.toLowerCase().includes('passivo circulante'))?.final_balance || 0);
      const pnc = Math.abs(accounts.find(a => a.account_code === '2.2' || a.account_name.toLowerCase().includes('passivo não circulante'))?.final_balance || 0);
      const pl = Math.abs(accounts.find(a => a.account_code === '2.3' || a.account_name.toLowerCase().includes('patrimônio líquido'))?.final_balance || 0);

      if ((ac + anc + pc + pnc + pl) === 0) return null;

      return [
          { name: 'Ativo', Circulante: ac, NaoCirculante: anc },
          { name: 'Passivo + PL', Circulante: pc, NaoCirculante: pnc, PatrimonioLiquido: pl }
