             <div className="p-8 h-[350px]">
                 <ResponsiveContainer width="100%" height="100%">
                     <BarChart data={balanceSheetChartData} layout="vertical" barSize={40} margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
                         <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#e2e8f0" />
                         <XAxis type="number" tickFormatter={(v) => new Intl.NumberFormat('pt-BR', { notation: 'compact' }).format(v)} />
                         <YAxis dataKey="name" type="category" width={100} />
                         <Tooltip formatter={(value: number) => formatCurrency(value)} />
                         <Legend />
                         <Bar dataKey="Circulante" stackId="a" fill="#3b82f6" name="Circulante" />
                         <Bar dataKey="NaoCirculante" stackId="a" fill="#1d4ed8" name="Não Circulante" />
                         <Bar dataKey="PatrimonioLiquido" stackId="a" fill="#10b981" name="Patrimônio Líquido" />
                     </BarChart>
                 </ResponsiveContainer>
             </div>
          </div>
      )}

      {/* Tabela de Contas */}
      <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 overflow-hidden">
         <div className="px-6 py-4 border-b dark:border-slate-700 flex flex-wrap justify-between items-center gap-4 bg-slate-50/50 dark:bg-slate-900/50">
            <h3 className="font-bold text-slate-800 dark:text-white">Livro Razão Analítico</h3>
            <div className="relative w-full md:w-64">
                <input 
                    type="text" 
                    placeholder="Filtrar contas..." 
                    value={searchTerm}
                    onChange={e => setSearchTerm(e.target.value)}
                    className="w-full pl-9 pr-4 py-2 text-sm border rounded-xl dark:bg-slate-800 dark:text-white dark:border-slate-600 focus:ring-2 focus:ring-blue-500"
                />
                <svg className="w-4 h-4 text-slate-400 absolute left-3 top-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
            </div>
         </div>

         <div className="overflow-auto max-h-[600px]">
          <table className="w-full text-left border-collapse">
            <thead className="sticky top-0 bg-white dark:bg-slate-800 z-10 shadow-sm">
              <tr className="text-[10px] font-black uppercase text-slate-400 border-b dark:border-slate-700">
                <th className="px-6 py-4">Código</th>
                <th className="px-6 py-4">Conta</th>
                <th className="px-6 py-4 text-center">Tipo</th>
                <th className="px-6 py-4 text-right">Saldo Anterior</th>
                <th className="px-6 py-4 text-right">Saldo Atual</th>
              </tr>
            </thead>
            <tbody className="divide-y dark:divide-slate-700">
                  {filteredAccounts.map((account, index) => (
                    <tr key={index} className={`hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors ${account.is_synthetic ? 'font-bold bg-slate-50/30 dark:bg-slate-800/20' : ''}`}>
                        <td className="px-6 py-4 text-xs font-mono text-blue-600">{account.account_code || '---'}</td>
                        <td className="px-6 py-4 text-sm text-slate-700 dark:text-slate-300">{getDisplayedName(account)}</td>
                        <td className="px-6 py-4 text-center">
