        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div className="flex-1">
                <h2 className="text-3xl font-black text-slate-900 dark:text-white leading-tight">
                    {headerData.companyName || 'Empresa em Análise'}
                </h2>
                <div className="flex flex-wrap gap-4 mt-3 text-sm font-medium">
                    <span className="bg-slate-100 dark:bg-slate-700 px-3 py-1 rounded-lg text-slate-600 dark:text-slate-300 flex items-center gap-2">
                        <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M7 7h.01M7 3h5c.512 0 1.024.195 1.414.586l7 7a2 2 0 010 2.828l-7 7a2 2 0 01-2.828 0l-7-7A1.994 1.994 0 013 12V7a4 4 0 014-4z" /></svg>
                        CNPJ: {headerData.cnpj || '---'}
                    </span>
                    <span className="bg-blue-50 dark:bg-blue-900/20 px-3 py-1 rounded-lg text-blue-700 dark:text-blue-300 flex items-center gap-2">
                        <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                        Período: {summary.period}
                    </span>
                </div>
            </div>
            <div className="text-right border-l-2 border-slate-100 dark:border-slate-700 pl-6 md:block hidden">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Responsável pela Análise</p>
                <p className="text-sm font-bold text-slate-800 dark:text-white">{headerData.collaboratorName}</p>
                <p className="text-[10px] text-slate-500 mt-0.5">{formattedDate}</p>
            </div>
        </div>

        {/* Mobile Responsável Info */}
        <div className="mt-6 pt-6 border-t border-slate-100 dark:border-slate-700 md:hidden">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Analista: {headerData.collaboratorName}</p>
            <p className="text-[10px] text-slate-500">{formattedDate}</p>
        </div>
      </div>

      {/* PARECER DA INTELIGÊNCIA ARTIFICIAL - ATIVO E PROEMINENTE */}
      <div className="bg-white dark:bg-slate-800 rounded-3xl shadow-2xl border-t-4 border-t-blue-600 border border-slate-200 dark:border-slate-700 overflow-hidden">
        <div className="px-8 py-6 bg-gradient-to-r from-blue-50 to-indigo-50 dark:from-slate-900/50 dark:to-slate-900/50 border-b dark:border-slate-700 flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
            <div className="flex items-center gap-4">
                <div className="bg-blue-600 p-3 rounded-2xl shadow-blue-500/40 shadow-lg">
                    <svg className="w-8 h-8 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" /></svg>
                </div>
                <div>
                    <h3 className="text-2xl font-black text-slate-800 dark:text-white tracking-tight">PARECER TÉCNICO IA</h3>
                    <p className="text-xs text-blue-600 font-bold uppercase tracking-widest">Exclusivo SP ASSESSORIA CONTÁBIL</p>
                </div>
            </div>

            <div className="flex bg-white dark:bg-slate-900 rounded-xl p-1.5 shadow-inner border dark:border-slate-700 w-full lg:w-auto overflow-x-auto">
                <button onClick={() => { setActiveTab('financial'); fetchFinancialOpinion(); }} className={`flex-1 lg:flex-none px-5 py-2 text-[10px] font-black uppercase tracking-wider rounded-lg transition-all ${activeTab === 'financial' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500'}`}>Saúde Financeira</button>
                <button onClick={() => { setActiveTab('costs'); fetchCostsOpinion(); }} className={`flex-1 lg:flex-none px-5 py-2 text-[10px] font-black uppercase tracking-wider rounded-lg transition-all ${activeTab === 'costs' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500'}`}>Auditoria de Custos</button>
                <button onClick={() => { setActiveTab('compliance'); fetchComplianceOpinion(); }} className={`flex-1 lg:flex-none px-5 py-2 text-[10px] font-black uppercase tracking-wider rounded-lg transition-all ${activeTab === 'compliance' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500'}`}>Fiscal/Compliance</button>
            </div>
