            ) : (
                <div className="animate-fadeIn">
                    {opinions[activeTab] ? (
                        <div className="prose dark:prose-invert max-w-none">
                            <div className="bg-slate-50 dark:bg-slate-900/80 p-8 rounded-3xl border border-slate-100 dark:border-slate-700 text-slate-700 dark:text-slate-300 leading-relaxed whitespace-pre-wrap font-sans text-lg">
                                {opinions[activeTab]}
                            </div>
                            <div className="mt-6 flex flex-col md:flex-row justify-between items-center gap-4 text-[9px] text-slate-400 font-bold uppercase tracking-[0.2em]">
                                <span className="flex items-center gap-2">
                                    <svg className="w-4 h-4 text-emerald-500" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>
                                    Relatório Gerado por Motor de IA Auditado - SP Assessoria Contábil
                                </span>
                                <span className="text-slate-300">desenvolvido by - SP Assessoria Contabil.</span>
                            </div>
                        </div>
                    ) : (
                        <div className="text-center py-20 border-2 border-dashed rounded-3xl border-slate-200 dark:border-slate-800">
                             <p className="text-slate-500 mb-6 font-medium">Parecer não disponível.</p>
                             <button 
                                onClick={() => {
                                    if(activeTab === 'financial') fetchFinancialOpinion();
                                    if(activeTab === 'costs') fetchCostsOpinion();
                                    if(activeTab === 'compliance') fetchComplianceOpinion();
                                }}
                                className="px-8 py-3 bg-blue-600 text-white rounded-xl font-black text-sm uppercase tracking-wider hover:bg-blue-700 transition-all shadow-xl shadow-blue-500/20"
                             >
                                Iniciar Análise Profissional
                             </button>
                        </div>
                    )}
                </div>
            )}
        </div>
      </div>

      {/* Métricas Principais */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-md border border-slate-100 dark:border-slate-700">
                <p className="text-[10px] font-black text-blue-600 uppercase tracking-widest mb-1">Total Débitos</p>
                <p className="text-2xl font-black text-slate-900 dark:text-white">{formatCurrency(summary.total_debits)}</p>
            </div>
