    doc.setFontSize(14);
    doc.text(headerData.companyName, 14, 50);
    doc.setFontSize(10);
    doc.text(`CNPJ: ${headerData.cnpj || 'N/A'}`, 14, 56);
    doc.text(`Período: ${summary.period}`, 80, 56);

