    doc.setFontSize(10);
    doc.text(`Total Débitos: ${formatCurrency(summary.total_debits)}`, 14, startY);
    doc.text(`Total Créditos: ${formatCurrency(summary.total_credits)}`, 80, startY);

    const resultColor = (summary.specific_result_value || 0) >= 0 ? [22, 163, 74] : [220, 38, 38]; // Green or Red
    doc.setTextColor(resultColor[0], resultColor[1], resultColor[2]);
    doc.text(`Resultado: ${formatCurrency(summary.specific_result_value || 0)}`, 150, startY);
