                    </span>
                </div>
            </div>
            <div className="text-right border-l-2 border-slate-100 dark:border-slate-700 pl-6 md:block hidden">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Responsável SP Assessoria</p>
                <p className="text-sm font-bold text-slate-800 dark:text-white">{headerData.collaboratorName}</p>
                <p className="text-[10px] text-slate-500 mt-0.5">{formattedDate}</p>
