        </div>
      </div>

      {/* CARDS DE TOTAIS - CORRIGIDO CONFORME SOLICITAÇÃO */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-md border-l-4 border-blue-500 border-t border-r border-b border-slate-100 dark:border-slate-700">
                <p className="text-[11px] font-black text-blue-600 uppercase tracking-widest mb-2">TOTAL DÉBITOS</p>
