      <div className="bg-white dark:bg-slate-800 rounded-3xl shadow-2xl border-t-4 border-t-blue-600 border border-slate-200 dark:border-slate-700 overflow-hidden">
        <div className="px-8 py-6 bg-gradient-to-r from-blue-50 to-indigo-50 dark:from-slate-900/50 dark:to-slate-900/50 border-b dark:border-slate-700 flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
            <div className="flex items-center gap-4">
