                <button onClick={() => { setActiveTab('costs'); fetchCostsOpinion(); }} className={`px-5 py-2 text-[10px] font-black uppercase tracking-wider rounded-lg transition-all ${activeTab === 'costs' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500'}`}>Gestão de Custos</button>
