        </div>
      </div>

      {/* ESTRUTURA PATRIMONIAL - VISUALIZAÇÃO EXPANDIDA */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="lg:col-span-2 bg-white dark:bg-slate-800 rounded-3xl shadow-xl border border-slate-200 dark:border-slate-700 overflow-hidden">
                <div className="px-8 py-5 border-b dark:border-slate-700 flex justify-between items-center bg-slate-50/50 dark:bg-slate-900/50">
                    <h3 className="font-black text-slate-800 dark:text-white uppercase">Estrutura Patrimonial</h3>
                    <span className="text-[10px] font-bold text-blue-600 uppercase tracking-widest">Visualização em Tempo Real</span>
                </div>
                <div className="p-10 h-[400px]">
                    <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={[
                            { name: 'Ativo', C: patrimonialData?.ac, NC: patrimonialData?.anc },
                            { name: 'Passivo/PL', C: patrimonialData?.pc, NC: patrimonialData?.pnc, PL: patrimonialData?.pl }
                        ]} layout="vertical" barSize={50}>
                            <CartesianGrid strokeDasharray="3 3" horizontal={false} />
                            <XAxis type="number" tickFormatter={(v) => `R$ ${v/1000}k`} />
                            <YAxis dataKey="name" type="category" width={80} tick={{fontWeight: 'bold'}} />
                            <Tooltip formatter={(v: number) => formatCurrency(v)} />
                            <Legend />
                            <Bar dataKey="C" name="Circulante" stackId="a" fill="#3b82f6" radius={[0, 0, 0, 0]} />
                            <Bar dataKey="NC" name="Não Circulante" stackId="a" fill="#1d4ed8" radius={[0, 4, 4, 0]} />
                            <Bar dataKey="PL" name="Patrimônio Líquido" stackId="a" fill="#10b981" radius={[0, 4, 4, 0]} />
                        </BarChart>
                    </ResponsiveContainer>
