            <div className="flex flex-col gap-4">
                <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow border border-slate-200 dark:border-slate-700">
                    <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Total do Ativo</p>
                    <p className="text-2xl font-black text-slate-900 dark:text-white">{formatCurrency(patrimonialData?.totalAtivo || 0)}</p>
                    <div className="mt-2 h-1.5 w-full bg-slate-100 rounded-full overflow-hidden">
                        <div className="h-full bg-blue-600" style={{ width: '100%' }}></div>
                    </div>
                </div>
                <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow border border-slate-200 dark:border-slate-700">
                    <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Patrimônio Líquido</p>
                    <p className="text-2xl font-black text-emerald-600">{formatCurrency(patrimonialData?.pl || 0)}</p>
                    <p className="text-xs text-slate-500 mt-1 font-bold">
                        {patrimonialData?.totalAtivo ? ((patrimonialData.pl / patrimonialData.totalAtivo) * 100).toFixed(1) : 0}% do Total
                    </p>
                </div>
                <div className="bg-blue-600 p-6 rounded-2xl shadow-xl text-white">
                    <p className="text-[10px] font-black uppercase opacity-60 mb-2">Equilíbrio Ativo vs Passivo</p>
                    <div className="flex items-center justify-between">
                        <p className="text-xl font-black">{summary.is_balanced ? 'CONSOLIDADO ✅' : 'DIVERGENTE ⚠️'}</p>
                    </div>
                    {!summary.is_balanced && (
                        <p className="text-xs mt-2 font-bold bg-white/20 p-2 rounded">Diferença: {formatCurrency(summary.discrepancy_amount)}</p>
                    )}
                </div>
            </div>
      </div>

      {/* LISTA DE CONTAS ANALÍTICA */}
      <div className="bg-white dark:bg-slate-800 rounded-3xl shadow-xl border border-slate-200 dark:border-slate-700 overflow-hidden">
         <div className="px-8 py-6 border-b dark:border-slate-700 flex flex-col sm:flex-row justify-between items-center gap-6 bg-slate-50/50 dark:bg-slate-900/50">
            <div>
                <h3 className="font-black text-slate-900 dark:text-white uppercase tracking-tight">Livro Razão Analítico</h3>
                <p className="text-xs text-slate-500 mt-1">Conferência detalhada com selo de qualidade SP Assessoria.</p>
            </div>
            <div className="relative w-full sm:w-80">
                <input 
                    type="text" 
                    placeholder="Filtrar contas ou códigos..." 
                    value={searchTerm}
                    onChange={e => setSearchTerm(e.target.value)}
                    className="w-full pl-10 pr-4 py-3 text-sm border-slate-200 rounded-2xl dark:bg-slate-800 dark:text-white dark:border-slate-700 focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all"
                />
                <svg className="w-5 h-5 text-slate-400 absolute left-3 top-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
            </div>
         </div>

         <div className="overflow-auto max-h-[700px]">
          <table className="w-full text-left border-collapse">
            <thead className="sticky top-0 bg-white dark:bg-slate-800 z-10 shadow-sm border-b dark:border-slate-700">
              <tr className="text-[10px] font-black uppercase text-slate-400 tracking-widest">
                <th className="px-8 py-5">Código</th>
                <th className="px-8 py-5">Conta Contábil</th>
                <th className="px-8 py-5 text-center">Natureza</th>
                <th className="px-8 py-5 text-right">Saldo Anterior</th>
                <th className="px-8 py-5 text-right">Saldo Atual</th>
              </tr>
            </thead>
            <tbody className="divide-y dark:divide-slate-700">
                  {filteredAccounts.map((account, index) => (
                    <tr key={index} className={`group hover:bg-blue-50/40 dark:hover:bg-blue-900/10 transition-colors ${account.is_synthetic ? 'font-bold bg-slate-50/30 dark:bg-slate-900/10' : ''}`}>
                        <td className="px-8 py-5 text-xs font-mono text-blue-600">{account.account_code || '---'}</td>
                        <td className="px-8 py-5 text-sm">
                            {renderAccountName(account)}
                        </td>
                        <td className="px-8 py-5 text-center">
                            <span className={`px-3 py-1 rounded-lg text-[9px] font-black tracking-widest ${account.type === 'Debit' ? 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400' : 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400'}`}>
                                {account.type === 'Debit' ? 'DÉBITO' : 'CRÉDITO'}
                            </span>
                        </td>
                        <td className="px-8 py-5 text-right text-xs font-mono text-slate-400">{formatCurrency(account.initial_balance)}</td>
                        <td className="px-8 py-5 text-right text-sm font-black text-slate-900 dark:text-white">
                            {formatCurrency(account.final_balance)}
                        </td>
                    </tr>
                  ))}
