          </table>
         </div>

         <div className="bg-slate-900 py-3 px-8 text-right border-t border-slate-800">
             <span className="text-[9px] font-bold text-slate-500 uppercase tracking-[0.2em]">desenvolvido by - SP Assessoria Contabil.</span>
         </div>
      </div>
