  );
};

export default AnalysisViewer;

import React, { useState, useMemo, useEffect } from 'react';
import { AnalysisResult, ExtractedAccount, HeaderData } from '../types';
import { generateFinancialInsight, generateCMVAnalysis, generateSpedComplianceCheck } from '../services/geminiService';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, Cell } from 'recharts';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';

interface Props {
  result: AnalysisResult;
  headerData: HeaderData;
  previousAccounts?: ExtractedAccount[];
  analysisTimestamp?: string | null;
}

const AnalysisViewer: React.FC<Props> = ({ result, headerData, previousAccounts, analysisTimestamp }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [activeTab, setActiveTab] = useState<'financial' | 'costs' | 'compliance'>('financial');

  const formattedDate = analysisTimestamp 
    ? new Date(analysisTimestamp).toLocaleString('pt-BR', { dateStyle: 'long', timeStyle: 'short' })
    : new Date().toLocaleString('pt-BR', { dateStyle: 'long', timeStyle: 'short' });

  const [opinions, setOpinions] = useState({ financial: '', costs: '', compliance: '' });
  const [loadingOpinions, setLoadingOpinions] = useState({ financial: false, costs: false, compliance: false });

  const formatCurrency = (value: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(value);

  const { summary, accounts = [], spell_check = [] } = result || {};

  // --- ACTIONS: PDF, SHARE, PRINT ---

  const handlePrint = () => {
    window.print();
  };

  const handleShare = async () => {
    const shareData = {
        title: `Auditoria: ${headerData.companyName}`,
        text: `Relatório de Análise Contábil - SP Assessoria.\nEmpresa: ${headerData.companyName}\nResultado: ${formatCurrency(summary.specific_result_value || 0)}`,
        url: window.location.href
    };

    try {
        if (navigator.share) {
            await navigator.share(shareData);
        } else {
            await navigator.clipboard.writeText(shareData.text);
            alert("Resumo copiado para a área de transferência!");
        }
    } catch (err) {
        console.error("Error sharing:", err);
    }
  };

  const handleExportPDF = () => {
    const doc = new jsPDF();

    // Header Institucional
    doc.setFillColor(15, 23, 42); // Slate 900
    doc.rect(0, 0, 210, 40, 'F');
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(18);
    doc.text("SP ASSESSORIA CONTÁBIL", 14, 20);
    doc.setFontSize(10);
    doc.text("Auditoria & Inteligência de Dados", 14, 26);
    doc.text(`Gerado em: ${formattedDate}`, 150, 20);
    doc.text(`Analista: ${headerData.collaboratorName}`, 150, 26);

    // Info Empresa
    doc.setTextColor(0, 0, 0);
    doc.setFontSize(14);
    doc.text(headerData.companyName, 14, 50);
    doc.setFontSize(10);
    doc.text(`CNPJ: ${headerData.cnpj || 'N/A'}`, 14, 56);
    doc.text(`Período: ${summary.period}`, 80, 56);

    // Totais
    doc.setDrawColor(200, 200, 200);
    doc.line(14, 60, 196, 60);
    doc.setFontSize(11);
    doc.text("RESUMO FINANCEIRO", 14, 68);

    const startY = 75;
    doc.setFontSize(10);
    doc.text(`Total Débitos: ${formatCurrency(summary.total_debits)}`, 14, startY);
    doc.text(`Total Créditos: ${formatCurrency(summary.total_credits)}`, 80, startY);

    const resultColor = (summary.specific_result_value || 0) >= 0 ? [22, 163, 74] : [220, 38, 38]; // Green or Red
    doc.setTextColor(resultColor[0], resultColor[1], resultColor[2]);
    doc.text(`Resultado: ${formatCurrency(summary.specific_result_value || 0)}`, 150, startY);
    doc.setTextColor(0,0,0);

    let currentY = startY + 15;

    // Parecer IA (se existir)
    if (opinions[activeTab]) {
        doc.setFontSize(11);
        doc.text(`PARECER TÉCNICO (${activeTab.toUpperCase()})`, 14, currentY);
        currentY += 7;
        doc.setFontSize(9);
        const splitText = doc.splitTextToSize(opinions[activeTab], 180);
        doc.text(splitText, 14, currentY);
        currentY += (splitText.length * 5) + 10;
    }

    // Tabela
    autoTable(doc, {
        startY: currentY,
        head: [['Código', 'Conta', 'Natureza', 'Saldo Anterior', 'Saldo Atual']],
        body: filteredAccounts.map(acc => [
            acc.account_code || '',
            acc.account_name,
            acc.type === 'Debit' ? 'D' : 'C',
            formatCurrency(acc.initial_balance),
            formatCurrency(acc.final_balance)
        ]),
        styles: { fontSize: 8 },
        headStyles: { fillColor: [37, 99, 235] },
        columnStyles: {
            3: { halign: 'right' },
            4: { halign: 'right', fontStyle: 'bold' }
        },
        didParseCell: (data) => {
            const rowIdx = data.row.index;
            const account = filteredAccounts[rowIdx];
            if (account && account.possible_inversion && data.section === 'body') {
                data.cell.styles.fillColor = [255, 237, 213]; // Orange 100
                data.cell.styles.textColor = [194, 65, 12]; // Orange 800
            }
        }
    });

    doc.save(`Relatorio_${headerData.companyName.replace(/\s+/g, '_')}.pdf`);
  };

  // --- DATA FETCHING ---

  const fetchFinancialOpinion = async () => {
      if (opinions.financial || loadingOpinions.financial) return;
      setLoadingOpinions(prev => ({ ...prev, financial: true }));
      try {
          const res = await generateFinancialInsight(result, "Realize um parecer completo sobre a saúde financeira, liquidez e rentabilidade desta empresa.", 5);
          setOpinions(prev => ({ ...prev, financial: res }));
      } catch (e) { console.error(e); }
      finally { setLoadingOpinions(prev => ({ ...prev, financial: false })); }
  };

  const fetchCostsOpinion = async () => {
      if (opinions.costs || loadingOpinions.costs) return;
      setLoadingOpinions(prev => ({ ...prev, costs: true }));
      try {
          const res = await generateCMVAnalysis(result, "IFRS 18");
          setOpinions(prev => ({ ...prev, costs: res }));
      } catch (e) { console.error(e); }
      finally { setLoadingOpinions(prev => ({ ...prev, costs: false })); }
  };

  const fetchComplianceOpinion = async () => {
      if (opinions.compliance || loadingOpinions.compliance) return;
      setLoadingOpinions(prev => ({ ...prev, compliance: true }));
      try {
          const res = await generateSpedComplianceCheck(result);
          setOpinions(prev => ({ ...prev, compliance: res }));
      } catch (e) { console.error(e); }
      finally { setLoadingOpinions(prev => ({ ...prev, compliance: false })); }
  };

  useEffect(() => {
      fetchFinancialOpinion();
  }, [result]);

  // --- HELPERS ---

  const isInvestmentAccount = (account: ExtractedAccount) => {
      const lowerName = account.account_name.toLowerCase();
      const code = account.account_code || '';
      return code.startsWith('1.2.1') || 
             lowerName.includes('investimento') || 
             lowerName.includes('participação') || 
             lowerName.includes('coligada') || 
             lowerName.includes('controlada');
  };

  const renderAccountName = (account: ExtractedAccount) => {
      const correction = spell_check.find(sc => sc.original_term.toLowerCase() === account.account_name.toLowerCase());
      const isInv = isInvestmentAccount(account);

      return (
          <div className="flex flex-col">
              <div className="flex items-center gap-2">
                  <span className={`${isInv ? 'text-red-600 font-bold' : 'text-slate-700 dark:text-slate-300'}`}>
                      {correction ? (
                          <span className="flex items-center gap-2">
                              <span className="line-through opacity-50">{account.account_name}</span>
                              <span className="text-blue-600 dark:text-blue-400">{correction.suggested_correction}</span>
                              <span className="bg-blue-100 dark:bg-blue-900/40 text-[8px] px-1 rounded font-black text-blue-700">IA</span>
                          </span>
                      ) : account.account_name}
                  </span>

                  {/* Google Search Link */}
                  <a 
                    href={`https://www.google.com/search?q=conta+contabil+${encodeURIComponent(account.account_name)}+detalhamento`} 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="p-1 hover:bg-slate-100 dark:hover:bg-slate-700 rounded transition-colors opacity-0 group-hover:opacity-100"
                    title="Validar conta no Google"
                  >
                    <svg className="w-3 h-3 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
                  </a>

                  {/* Inversion Warning Icon */}
                  {account.possible_inversion && (
                      <div className="group/tooltip relative">
