import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';

interface Props {
  result: AnalysisResult;
  headerData: HeaderData;
  previousAccounts?: ExtractedAccount[];
  analysisTimestamp?: string | null;
}

const AnalysisViewer: React.FC<Props> = ({ result, headerData, previousAccounts, analysisTimestamp }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [activeTab, setActiveTab] = useState<'financial' | 'costs' | 'compliance'>('financial');
  const [acceptedCorrections, setAcceptedCorrections] = useState<Record<string, string>>({}); // Store accepted spell checks

  const formattedDate = analysisTimestamp 
    ? new Date(analysisTimestamp).toLocaleString('pt-BR', { dateStyle: 'long', timeStyle: 'short' })
    : new Date().toLocaleString('pt-BR', { dateStyle: 'long', timeStyle: 'short' });

  const [opinions, setOpinions] = useState({ financial: '', costs: '', compliance: '' });
  const [loadingOpinions, setLoadingOpinions] = useState({ financial: false, costs: false, compliance: false });

  const formatCurrency = (value: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(value);

  const { summary, accounts = [], spell_check = [] } = result || {};

  // --- ACTIONS: PDF, SHARE, PRINT ---

  const handlePrint = () => {
    window.print();
  };

  const handleShare = async () => {
    const shareData = {
        title: `Auditoria: ${headerData.companyName}`,
        text: `Relatório de Análise Contábil - SP Assessoria.\nEmpresa: ${headerData.companyName}\nResultado: ${formatCurrency(summary.specific_result_value || 0)}`,
        url: window.location.href
    };

    try {
        if (navigator.share) {
            await navigator.share(shareData);
        } else {
            await navigator.clipboard.writeText(shareData.text);
            alert("Resumo copiado para a área de transferência!");
        }
    } catch (err) {
        console.error("Error sharing:", err);
    }
  };

  const handleExportPDF = () => {
    const doc = new jsPDF();

    // Header Institucional
    doc.setFillColor(15, 23, 42); // Slate 900
    doc.rect(0, 0, 210, 40, 'F');
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(18);
    doc.text("SP ASSESSORIA CONTÁBIL", 14, 20);
    doc.setFontSize(10);
    doc.text("Auditoria & Inteligência de Dados", 14, 26);
    doc.text(`Gerado em: ${formattedDate}`, 150, 20);
    doc.text(`Analista: ${headerData.collaboratorName}`, 150, 26);

    // Info Empresa
    doc.setTextColor(0, 0, 0);
    doc.setFontSize(14);
    doc.text(headerData.companyName, 14, 50);
    doc.setFontSize(10);
    doc.text(`CNPJ: ${headerData.cnpj || 'N/A'}`, 14, 56);
    doc.text(`Período: ${summary.period}`, 80, 56);

    // Totais
    doc.setDrawColor(200, 200, 200);
    doc.line(14, 60, 196, 60);
    doc.setFontSize(11);
    doc.text("RESUMO FINANCEIRO", 14, 68);

    const startY = 75;
    doc.setFontSize(10);
    doc.text(`Total Débitos: ${formatCurrency(summary.total_debits)}`, 14, startY);
    doc.text(`Total Créditos: ${formatCurrency(summary.total_credits)}`, 80, startY);

    const resultColor = (summary.specific_result_value || 0) >= 0 ? [22, 163, 74] : [220, 38, 38]; // Green or Red
    doc.setTextColor(resultColor[0], resultColor[1], resultColor[2]);
    doc.text(`Resultado: ${formatCurrency(summary.specific_result_value || 0)}`, 150, startY);
    doc.setTextColor(0,0,0);

    let currentY = startY + 15;

    // Parecer IA (se existir)
    if (opinions[activeTab]) {
        doc.setFontSize(11);
        doc.text(`PARECER TÉCNICO (${activeTab.toUpperCase()})`, 14, currentY);
        currentY += 7;
