// Helper for Exponential Backoff
async function retryWithBackoff<T>(fn: () => Promise<T>, retries = 3, baseDelay = 3000): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    const message = error?.message || '';
    const status = error?.status || error?.code;

    if (message.includes('404') || message.includes('not found')) {
        throw error;
    }

    if (retries > 0) {
      console.warn(`API Error (${status}). Retrying in ${baseDelay}ms...`);
      await new Promise(resolve => setTimeout(resolve, baseDelay));
      return retryWithBackoff(fn, retries - 1, baseDelay * 2);
    }
    throw error;
  }
}

function safeDecodeBase64(str: string): string {
    try {
        return decodeURIComponent(escape(window.atob(str)));
    } catch (e) {
        return window.atob(str);
    }
}

function parseFinancialNumber(val: any): number {
  if (typeof val === 'number') return val;
  if (!val) return 0;

  let clean = String(val).trim();

  // Quick return for empty or non-numeric looking strings
  if (!clean || clean === '-' || clean === '–') return 0;

  // Fix common OCR errors
  clean = clean.replace(/O/gi, '0')
               .replace(/l/g, '1') // Lowercase L to 1
               .replace(/[^0-9.,\-()]/g, ''); // Keep only numbers, dots, commas, minus, parens

  // Handle Parentheses as Negative
  const isNegativeParens = /^\(.*\)$/.test(clean);
  if (isNegativeParens) {
      clean = clean.replace(/[()]/g, '');
  }

  // Handle trailing D/C (Debit/Credit) indicators if they slipped into the value string
  // (Though regex above removed letters, sometimes they are attached to numbers in raw input before this func)

  // IMPORTANT: Brazilian Format Detection (1.000,00) vs US (1,000.00)
  const lastDotIndex = clean.lastIndexOf('.');
  const lastCommaIndex = clean.lastIndexOf(',');

  if (lastCommaIndex > lastDotIndex) {
      // Brazilian format: remove dots, replace comma with dot
      clean = clean.replace(/\./g, '').replace(',', '.');
  } else if (lastDotIndex > lastCommaIndex) {
      // US format: remove commas
      clean = clean.replace(/,/g, '');
  } else {
      // No separator or only one type. 
      // If it has a comma, treat as decimal separator (common in BR)
      if (clean.includes(',')) clean = clean.replace(',', '.');
  }

  let num = parseFloat(clean);

  if (isNaN(num)) return 0;
  if (isNegativeParens) num = -Math.abs(num);

  return num;
}

function checkInversion(name: string, type: 'Debit' | 'Credit', finalBalance: number, indicator: string | null, code: string): boolean {
    const lowerName = name.toLowerCase();
    let expectedNature: 'Debit' | 'Credit' | 'Unknown' = 'Unknown';
    if (code.startsWith('1')) expectedNature = 'Debit';
    else if (code.startsWith('2')) expectedNature = 'Credit';
    else if (code.startsWith('3') || lowerName.includes('receita') || lowerName.includes('faturamento')) expectedNature = 'Credit';
    else if (code.startsWith('4') || lowerName.includes('despesa') || lowerName.includes('custo')) expectedNature = 'Debit';

    const contraKeywords = [
        'deprecia', 'amortiza', 'exaust', 'pdd', 'perdas estimadas', 'crédito de liquidação duvidosa',
        'ajuste a valor presente', 'ações em tesouraria', 'prejuízos acumulados', 'capital a integralizar',
        'redutora', 'devolução de vendas', 'impostos sobre vendas', 'cancelamento de vendas', 'abatimentos'
    ];

    const isContraAccount = contraKeywords.some(k => lowerName.includes(k));
    if (isContraAccount && expectedNature !== 'Unknown') {
        expectedNature = expectedNature === 'Debit' ? 'Credit' : 'Debit';
    }

    let actualNature: 'Debit' | 'Credit' = type;
    if (indicator) {
        if (indicator.toUpperCase() === 'D') actualNature = 'Debit';
        if (indicator.toUpperCase() === 'C') actualNature = 'Credit';
    } else {
        if (finalBalance < 0) actualNature = 'Credit'; 
    }

    if (expectedNature !== 'Unknown' && expectedNature !== actualNature) return true;
    return false;
}

function mapValuesToColumns(numbers: number[], docType: string): { initial: number, debit: number, credit: number, final: number } {
    // Filter out NaN or 0s that might be parsing errors if we have too many "values"
    // But be careful, 0 is a valid balance.

    const count = numbers.length;
    let initial = 0, debit = 0, credit = 0, final = 0;

    if (count === 1) {
        final = numbers[0];
    } else if (count === 2) {
        // Usually Previous Balance | Final Balance
        // OR Final Balance | Percentage (common in some DREs)
        // We assume Balances for now.
        initial = numbers[0];
        final = numbers[1];
    } else if (count === 3) {
        // Debit | Credit | Final
        debit = numbers[0];
        credit = numbers[1];
        final = numbers[2];
    } else if (count >= 4) {
        // Initial | Debit | Credit | Final
        initial = numbers[0];
        debit = numbers[1];
        credit = numbers[2];
        final = numbers[3];
    }

    return { initial, debit, credit, final };
}

function normalizeFinancialData(rawLines: string[], docType: string): AnalysisResult {
  const accounts: ExtractedAccount[] = [];

  // Improved parsing logic: Split by pipe '|' instead of relying on complex regex
  rawLines.forEach(line => {
      const cleanLine = line.trim();
      if (!cleanLine || cleanLine.length < 5) return;
      if (/^(doctype|data|conta|descri|saldo|débito|crédito|página|page|cod|cód)/i.test(cleanLine)) return;

      const parts = cleanLine.split('|').map(p => p.trim());

      if (parts.length < 2) return; // Needs at least Name and Value

      let code = '';
      let name = '';
      let valuesPart: string[] = [];

      // Heuristic: If part 0 looks like a code (numbers/dots), assume Code | Name | Values
      // Otherwise assume Name | Values (Code might be merged or missing)
      const firstPartIsCode = /^[\d.-]+$/.test(parts[0]) && parts[0].length < 20;

      if (firstPartIsCode) {
          code = parts[0];
          name = parts[1];
          valuesPart = parts.slice(2);
      } else {
          // If the first part is long or contains letters, it's likely the name.
          // Sometimes Code and Name are merged "1.1.1 Caixa"
          const splitSpace = parts[0].match(/^([\d.-]+)\s+(.+)$/);
          if (splitSpace) {
              code = splitSpace[1];
              name = splitSpace[2];
          } else {
              name = parts[0];
          }
          valuesPart = parts.slice(1);
      }

      if (!name || name.length < 2) return;

      // Filter out empty parts in values and parse
      const numbers = valuesPart
          .filter(v => v !== '')
          .map(v => parseFinancialNumber(v));

      if (numbers.length === 0) return;

      let type: 'Debit' | 'Credit' = 'Debit';
      const lowerName = name.toLowerCase();
      if (code.startsWith('2') || code.startsWith('3') || code.startsWith('6') || 
          lowerName.includes('passivo') || lowerName.includes('fornecedor') || 
          lowerName.includes('receita') || lowerName.includes('patrimônio') || lowerName.includes('capital')) {
          type = 'Credit';
      }

      const values = mapValuesToColumns(numbers, docType);
      const cleanCode = code.endsWith('.') ? code.slice(0, -1) : code;

      let category = null;
      if (docType === 'DRE' || code.startsWith('3') || code.startsWith('4') || code.startsWith('5')) {
           if (lowerName.includes('receita') || lowerName.includes('custo') || lowerName.includes('despesa') || code.startsWith('3') || code.startsWith('4')) category = 'Operacional';
           else if (lowerName.includes('invest') || lowerName.includes('imobiliz')) category = 'Investimento';
           else if (lowerName.includes('juro') || lowerName.includes('financ')) category = 'Financiamento';
           else category = 'Operacional';
      }

      const possibleInversion = checkInversion(name, type, values.final, null, cleanCode);

      // Additional safety check: If final balance is 0 but debit/credit exist, use them
      let finalBal = values.final;
      if (finalBal === 0 && (values.debit !== 0 || values.credit !== 0)) {
          finalBal = values.debit - values.credit; // Simplistic approximation if final missing
      }

      accounts.push({
          account_code: cleanCode,
          account_name: name,
          initial_balance: values.initial,
          debit_value: values.debit,
          credit_value: values.credit,
          final_balance: finalBal,
          total_value: finalBal,
          type,
          possible_inversion: possibleInversion,
          ifrs18_category: category as any,
          level: 1, 
          is_synthetic: false
      });
  });

  // Post-processing hierarchy
  accounts.sort((a, b) => {
      if (!a.account_code) return 1;
      if (!b.account_code) return -1;
      return a.account_code.localeCompare(b.account_code, undefined, { numeric: true, sensitivity: 'base' });
  });

  accounts.forEach((acc, idx) => {
      if (acc.account_code) {
          acc.level = acc.account_code.split(/[.-]/).filter(x => x.length > 0).length;
          const myCode = acc.account_code;
          let isParent = false;
          const nextAcc = accounts[idx + 1];
          if (nextAcc && nextAcc.account_code && nextAcc.account_code.startsWith(myCode)) {
               const charAfter = nextAcc.account_code[myCode.length];
               if (charAfter === '.' || charAfter === '-' || charAfter === undefined) isParent = true;
          }
          acc.is_synthetic = isParent;
      } else if (acc.account_name.toLowerCase().startsWith('total') || acc.account_name.toLowerCase().startsWith('grupo')) {
          acc.is_synthetic = true;
      }
  });

  const analyticalAccounts = accounts.filter(a => !a.is_synthetic);
  const calcAccounts = analyticalAccounts.length > 0 ? analyticalAccounts : accounts.filter(a => !a.account_name.toLowerCase().includes('total'));

  const total_debits = calcAccounts.reduce((sum, a) => sum + Math.abs(a.debit_value), 0);
  const total_credits = calcAccounts.reduce((sum, a) => sum + Math.abs(a.credit_value), 0);
  const discrepancy = Math.abs(total_debits - total_credits);

  let revenueSum = 0, expenseSum = 0, resultAccountsFound = false;

  analyticalAccounts.forEach(acc => {
      if (acc.account_code) {
          const firstChar = acc.account_code.charAt(0);
          if (['3', '4', '5', '6', '7'].includes(firstChar)) {
              resultAccountsFound = true;
              if (acc.type === 'Credit') revenueSum += Math.abs(acc.final_balance);
              if (acc.type === 'Debit') expenseSum += Math.abs(acc.final_balance);
          }
      } else {
         const lower = acc.account_name.toLowerCase();
         if ((lower.includes('receita') || lower.includes('faturamento')) && acc.type === 'Credit') { revenueSum += Math.abs(acc.final_balance); resultAccountsFound = true; }
         if ((lower.includes('despesa') || lower.includes('custo')) && acc.type === 'Debit') { expenseSum += Math.abs(acc.final_balance); resultAccountsFound = true; }
      }
  });

  let calculatedResult = revenueSum - expenseSum;
  let resultLabel = calculatedResult >= 0 ? 'Lucro Apurado' : 'Prejuízo Apurado';

  if (Math.abs(calculatedResult) < 0.01 || docType === 'DRE') {
      const resultAccount = analyticalAccounts.find(a => 
          (a.account_code?.startsWith('2') || !a.account_code) && 
          (
            /resultado\s+do\s+(exerc|per|periodo)/i.test(a.account_name) ||
            /lucro\s+l[ií]quido/i.test(a.account_name) ||
            /preju[ií]zo\s+l[ií]quido/i.test(a.account_name) ||
            /lucros\s+acumulados/i.test(a.account_name) ||
            /preju[ií]zos\s+acumulados/i.test(a.account_name) ||
            /super[aá]vit/i.test(a.account_name) ||
            /d[eé]ficit/i.test(a.account_name)
          )
      );

      if (resultAccount) {
          let val = Math.abs(resultAccount.final_balance);
          if (/preju|d[eé]ficit/i.test(resultAccount.account_name)) {
              calculatedResult = -val;
          } else if (resultAccount.type === 'Credit' || resultAccount.final_balance < 0) {
              calculatedResult = val;
          } else {
              calculatedResult = -val;
          }
          resultLabel = resultAccount.account_name;
      }
  }

  return {
      summary: {
          document_type: docType as any,
          period: 'A definir',
          total_debits,
          total_credits,
          is_balanced: discrepancy < 1.0,
          discrepancy_amount: discrepancy,
          observations: [],
          specific_result_value: calculatedResult,
          specific_result_label: resultLabel
      },
      accounts,
      spell_check: []
  };
}

async function extractRawData(ai: GoogleGenAI, fileBase64: string, mimeType: string): Promise<{lines: string[], docType: string}> {
    const safetySettings = [
        { category: HarmCategory.HARM_CATEGORY_HATE_SPEECH, threshold: HarmBlockThreshold.BLOCK_NONE },
        { category: HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT, threshold: HarmBlockThreshold.BLOCK_NONE },
        { category: HarmCategory.HARM_CATEGORY_HARASSMENT, threshold: HarmBlockThreshold.BLOCK_NONE },
        { category: HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT, threshold: HarmBlockThreshold.BLOCK_NONE },
    ];

    const basePrompt = `
    ROLE: Auditor Contábil Senior.
    TASK: Extraia os dados da tabela financeira.

    IMPORTANT:
    - OBRIGATÓRIO usar o caractere '|' (pipe) para separar colunas.
    - NÃO altere os valores. Mantenha os decimais originais (ex: 1.000,00).
    - Ignore cabeçalhos repetidos e rodapés.
    - Se houver colunas vazias, deixe o espaço entre pipes vazio (ex: ||).

    OUTPUT FORMAT:
    DOCTYPE: [Balancete/DRE/Balanço]
    CÓDIGO | NOME DA CONTA | SALDO_ANTERIOR | DÉBITO | CRÉDITO | SALDO_ATUAL
    `;

    try {
        let extractedText = "";
        let docType = 'Balancete';

        if (mimeType === 'text/csv' || mimeType === 'text/plain' || mimeType === 'application/csv') {
            const decodedText = safeDecodeBase64(fileBase64);
            const allLines = decodedText.split('\n');
            const CHUNK_SIZE = 1500; 
            const chunks: string[] = [];
            for (let i = 0; i < allLines.length; i += CHUNK_SIZE) chunks.push(allLines.slice(i, i + CHUNK_SIZE).join('\n'));

            for (let i = 0; i < chunks.length; i++) {
                const response = await retryWithBackoff<GenerateContentResponse>(() => ai.models.generateContent({
                    model: 'gemini-3-flash-preview',
                    contents: { parts: [{ text: basePrompt + `\n\n--- INPUT DATA PART ${i+1} ---\n${chunks[i]}\n--- END PART ---` }]},
                    config: { temperature: 0.0, maxOutputTokens: 8192, safetySettings }
                }));
                if (response.text) extractedText += response.text + "\n";
            }
        } else {
            const response = await retryWithBackoff<GenerateContentResponse>(() => ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: { parts: [
                    { inlineData: { mimeType: mimeType, data: fileBase64 } },
                    { text: basePrompt }
                ]},
                config: { temperature: 0.0, maxOutputTokens: 65000, safetySettings }
            }));
            extractedText = response.text || "";
        }

        let lines = extractedText.split('\n').filter(l => l.trim().length > 0);
        const docTypeLine = lines.find(l => l.trim().toUpperCase().startsWith('DOCTYPE:'));

        if (docTypeLine) {
            const typeVal = docTypeLine.split(':')[1]?.trim().toUpperCase() || '';
            if (typeVal.includes('DRE')) docType = 'DRE';
            else if (typeVal.includes('BALANCETE')) docType = 'Balancete';
            else if (typeVal.includes('BALANÇO')) docType = 'Balanço Patrimonial';
            lines = lines.filter(l => !l.toUpperCase().startsWith('DOCTYPE:'));
        }

        // Less strict filter: Keep lines that have at least one digit OR a pipe
        lines = lines.filter(l => /\d/.test(l) || l.includes('|'));
        return { lines, docType };

    } catch (e: any) {
        console.error("Extraction Error:", e);
        throw new Error(`Erro na extração: ${e.message}`);
    }
}

async function generateNarrativeAnalysis(ai: GoogleGenAI, summaryData: any, sampleAccounts: string[]): Promise<{observations: string[], spellcheck: any[], period: string}> {
    const prompt = `
    ATUE COMO: Auditor Contábil Senior SP Assessoria.
    DADOS: Doc: ${summaryData.document_type}, Resultado: ${summaryData.specific_result_value}.
    AMOSTRA CONTAS: ${sampleAccounts.join('; ')}

    TAREFA: 
    1. Identifique o período (ex: 01/2025).
    2. Identifique erros ortográficos técnicos nas contas da amostra (ex: "Despessa" -> "Despesa").

    SAÍDA JSON:
    {
      "period": "01/01/2025 a 31/12/2025",
      "observations": ["Destaque 1"],
      "spellcheck": [{"original_term": "RESEITA", "suggested_correction": "RECEITA", "confidence": "High"}]
    }
    `;
    try {
        const response = await retryWithBackoff<GenerateContentResponse>(() => ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: { parts: [{ text: prompt }] },
            config: { responseMimeType: "application/json", temperature: 0.4 }
        }));
        const parsed = JSON.parse(response.text || '{}');
        return {
            period: parsed.period || "A definir",
            observations: parsed.observations || [],
            spellcheck: parsed.spellcheck || []
        };
    } catch (e) { return { observations: [], spellcheck: [], period: "Indefinido" }; }
}

export const analyzeDocument = async (fileBase64: string, mimeType: string): Promise<AnalysisResult> => {
  if (!process.env.API_KEY) throw new Error("API Key not found.");
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const { lines, docType } = await extractRawData(ai, fileBase64, mimeType);
  if (lines.length === 0) throw new Error("Nenhum dado extraído.");
  const result = normalizeFinancialData(lines, docType);
  const sample = result.accounts.slice(0, 150).map(a => a.account_name);
  const narrative = await generateNarrativeAnalysis(ai, result.summary, sample);
  result.summary.period = narrative.period || 'Período não identificado';
  result.summary.observations = narrative.observations || [];
  result.spell_check = narrative.spellcheck || [];
  return result;
};

