// --- CONSOLIDATION TYPES ---
export interface ConsolidatedCompany {
  id: string;
  name: string;
  cnpj: string;
}

export interface ConsolidatedRow {
  code: string;
  name: string;
  is_synthetic: boolean;
  level: number;
  values: { [companyId: string]: number }; // Value per company
  total: number; // Sum of all companies
}

export interface ConsolidationResult {
  companies: ConsolidatedCompany[];
  rows: ConsolidatedRow[];
  generatedAt: string;
  groupName: string; // Usually derived from first company or generic
}

import { AnalysisResult, HistoryItem, ConsolidationResult, ConsolidatedRow, ConsolidatedCompany } from "../types";

// Helper to normalize account keys for merging
const getAccountKey = (code: string | null, name: string): string => {
    // Priority: Code. If code exists, use it as primary key (stripping dots for loose matching).
    // If no code, use normalized name.
    if (code && code.length > 0) {
        return code.replace(/[^0-9]/g, ''); 
    }
    return name.trim().toUpperCase();
};

export const consolidateDREs = (items: { item: HistoryItem, result: AnalysisResult }[]): ConsolidationResult => {
    const companies: ConsolidatedCompany[] = items.map(i => ({
        id: i.item.id,
        name: i.item.headerData.companyName,
        cnpj: i.item.headerData.cnpj
    }));

    const accountMap = new Map<string, ConsolidatedRow>();

    // 1. Iterate over all companies to build the superset of accounts
    items.forEach(({ item, result }) => {
        result.accounts.forEach(acc => {
            const key = getAccountKey(acc.account_code, acc.account_name);

            if (!accountMap.has(key)) {
                accountMap.set(key, {
                    code: acc.account_code || '',
                    name: acc.account_name,
                    is_synthetic: acc.is_synthetic,
                    level: acc.level,
                    values: {},
                    total: 0
                });
            }

            const row = accountMap.get(key)!;

            // Populate value for this company
            // Ensure we initialize if undefined
            if (row.values[item.id] === undefined) row.values[item.id] = 0;

            // Add value (Assuming final_balance represents the DRE line value)
            // Note: In our extraction logic, final_balance for DRE is the line amount.
            row.values[item.id] = acc.final_balance;
        });
    });

    // 2. Calculate Totals and finalize rows
    const rows = Array.from(accountMap.values()).map(row => {
        let sum = 0;
        companies.forEach(company => {
            const val = row.values[company.id] || 0;
            row.values[company.id] = val; // Ensure 0 instead of undefined
            sum += val;
        });
        row.total = sum;
        return row;
    });

    // 3. Sort rows by Code
    rows.sort((a, b) => {
        // Handle rows without codes (push to bottom or sort by name)
        if (!a.code && !b.code) return 0;
        if (!a.code) return 1;
        if (!b.code) return -1;

        // Natural sort for "1.01", "1.02", "1.10"
        return a.code.localeCompare(b.code, undefined, { numeric: true, sensitivity: 'base' });
    });

    // 4. Recalculate Result (Lucro/Prejuízo) explicitly to ensure math consistency
    // (Optional, depends if the rows contain the calculated result or just lines)
    // We rely on the rows extracted.

    return {
        companies,
        rows,
        generatedAt: new Date().toISOString(),
        groupName: companies.length > 0 ? `${companies[0].name} e Outras` : 'Grupo Econômico'
    };
};

import React, { useState } from 'react';
import { ConsolidationResult } from '../types';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';

interface Props {
    data: ConsolidationResult;
    onBack: () => void;
    collaboratorName: string;
}

const ConsolidationViewer: React.FC<Props> = ({ data, onBack, collaboratorName }) => {
    const [searchTerm, setSearchTerm] = useState('');

    const formatCurrency = (value: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(value);
    const formattedDate = new Date(data.generatedAt).toLocaleString('pt-BR', { dateStyle: 'long', timeStyle: 'medium' });

    // Filter Logic
    const filteredRows = data.rows.filter(r => 
        r.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
        r.code.includes(searchTerm)
    );

    const handleExportPDF = () => {
        const doc = new jsPDF('l'); // Landscape for many columns
        const pageWidth = doc.internal.pageSize.width;

        // --- STANDARD HEADER (Reused logic, adapted for landscape) ---
        doc.setFillColor(15, 23, 42); 
        doc.rect(0, 0, pageWidth, 40, 'F');

        doc.setTextColor(255, 255, 255);
        doc.setFontSize(18);
        doc.setFont("helvetica", "bold");
        doc.text("SP ASSESSORIA CONTÁBIL", 14, 15);

        doc.setFontSize(10);
        doc.setFont("helvetica", "normal");
        doc.text(`Relatório de Consolidação (Grupo Econômico)`, 14, 22);

        // Metadata
        doc.text(`Empresas: ${data.companies.length} Entidades`, 14, 30);
        doc.text(`Grupo Base: ${data.groupName}`, 14, 35);

        doc.text(`Emissão: ${formattedDate}`, pageWidth - 14, 30, { align: 'right' });
        doc.text(`Operador: ${collaboratorName || 'Não Identificado'}`, pageWidth - 14, 35, { align: 'right' });

        // Table Data Preparation
        const headRow = ['Código', 'Conta', ...data.companies.map(c => c.name.substring(0, 15) + '...'), 'TOTAL GRUPO'];
        const bodyRows = filteredRows.map(row => {
            const rowData = [
                row.code,
                row.name,
                ...data.companies.map(c => formatCurrency(row.values[c.id])),
                { content: formatCurrency(row.total), styles: { fontStyle: 'bold', fillColor: [240, 240, 240] } }
            ];
            return rowData;
        });

        autoTable(doc, {
            startY: 50,
            head: [headRow],
            body: bodyRows as any[],
            styles: { fontSize: 7, cellPadding: 2 },
            headStyles: { fillColor: [37, 99, 235], halign: 'center' },
            columnStyles: {
                0: { cellWidth: 20 }, // Code
                1: { cellWidth: 50 }, // Name
                // Dynamic columns will auto-size
            },
            didDrawPage: (d) => {
                 // Footer
                 const pageSize = doc.internal.pageSize;
                 const pageHeight = pageSize.height ? pageSize.height : pageSize.getHeight();
                 doc.setFontSize(8);
                 doc.setTextColor(150);
                 doc.text(`Página ${d.pageNumber} - Gerado por SP Assessoria System`, 14, pageHeight - 10);
                 doc.text(`${formattedDate}`, pageWidth - 14, pageHeight - 10, { align: 'right' });
            }
        });

        doc.save(`Consolidado_Grupo_${new Date().toISOString().split('T')[0]}.pdf`);
    };

    // Calculate Total Result for Summary Card
    const totalResult = data.rows.find(r => 
        r.name.toLowerCase().includes('lucro líquido') || 
        r.name.toLowerCase().includes('resultado do exercício') ||
        r.name.toLowerCase().includes('prejuízo líquido')
    )?.total || 0;

    return (
        <div className="space-y-6 animate-fadeIn pb-20">
            {/* Header / Summary */}
            <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 flex flex-col md:flex-row justify-between items-center gap-4">
                <div>
                    <h2 className="text-2xl font-black text-slate-800 dark:text-white flex items-center gap-2">
                        <span className="bg-purple-600 text-white text-xs px-2 py-1 rounded">GRUPO</span>
                        Consolidação de DREs
                    </h2>
                    <div className="flex gap-2 text-sm text-slate-500 mt-1">
                        <span>{data.companies.length} Empresas Selecionadas</span>
                        <span>•</span>
                        <span>{formattedDate}</span>
                    </div>
                </div>
                <div className="flex gap-2">
                    <button onClick={onBack} className="px-4 py-2 border rounded-lg hover:bg-slate-50 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-300 font-bold text-xs">
                        Voltar
                    </button>
                    <button onClick={handleExportPDF} className="flex items-center gap-2 px-4 py-2 bg-purple-600 text-white rounded-lg font-bold text-xs hover:bg-purple-700 shadow-lg shadow-purple-500/20">
                        <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                        Exportar Consolidação (PDF)
                    </button>
                </div>
            </div>

            {/* Matrix View */}
            <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 overflow-hidden">
                <div className="p-4 border-b dark:border-slate-700 flex justify-between items-center bg-slate-50 dark:bg-slate-900/50">
                     <input 
                        type="text" 
                        placeholder="Filtrar contas consolidadas..." 
                        value={searchTerm}
                        onChange={e => setSearchTerm(e.target.value)}
                        className="p-2 text-sm rounded border w-64 dark:bg-slate-700 dark:text-white"
                    />
                    <div className="text-sm font-bold text-slate-700 dark:text-slate-300">
                        Resultado Aglutinado: <span className={totalResult >= 0 ? 'text-green-600' : 'text-red-600'}>{formatCurrency(totalResult)}</span>
                    </div>
                </div>

                <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left">
                        <thead className="bg-slate-100 dark:bg-slate-900 text-slate-600 dark:text-slate-400 font-bold sticky top-0 z-10">
                            <tr>
                                <th className="p-3 border-r dark:border-slate-700 min-w-[100px]">Código</th>
                                <th className="p-3 border-r dark:border-slate-700 min-w-[200px]">Conta</th>
                                {data.companies.map(c => (
                                    <th key={c.id} className="p-3 text-right border-r dark:border-slate-700 min-w-[140px] bg-slate-50 dark:bg-slate-800">
                                        <div className="truncate w-full" title={c.name}>{c.name}</div>
                                        <div className="text-[9px] font-mono font-normal text-slate-400">{c.cnpj}</div>
                                    </th>
                                ))}
                                <th className="p-3 text-right bg-purple-50 dark:bg-purple-900/20 text-purple-700 dark:text-purple-300 min-w-[140px]">
                                    TOTAL GRUPO
                                </th>
                            </tr>
                        </thead>
                        <tbody className="divide-y dark:divide-slate-700">
                            {filteredRows.map((row, idx) => (
                                <tr key={idx} className={`hover:bg-slate-50 dark:hover:bg-slate-800 ${row.is_synthetic ? 'font-bold bg-slate-50/50' : ''}`}>
                                    <td className="p-3 font-mono text-xs text-slate-500 border-r dark:border-slate-700">{row.code}</td>
                                    <td className="p-3 border-r dark:border-slate-700 truncate max-w-xs" title={row.name}>{row.name}</td>
                                    {data.companies.map(c => (
                                        <td key={c.id} className="p-3 text-right font-mono text-slate-500 border-r dark:border-slate-700">
                                            {formatCurrency(row.values[c.id])}
                                        </td>
                                    ))}
                                    <td className={`p-3 text-right font-mono font-bold bg-purple-50/30 dark:bg-purple-900/10 ${row.total < 0 ? 'text-red-600' : 'text-slate-800 dark:text-slate-200'}`}>
                                        {formatCurrency(row.total)}
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

export default ConsolidationViewer;

import React, { useState, useMemo, useEffect } from 'react';
import { HistoryItem } from '../types';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  history: HistoryItem[];
  onSelect: (item: HistoryItem) => void;
  onClear: () => void;
  onDeleteItem?: (id: string) => void;
  onCompare?: (item1: HistoryItem, item2: HistoryItem) => void;
  onConsolidate?: (items: HistoryItem[]) => void;
  currentUser?: string;
}

const ITEMS_PER_PAGE = 8;

const HistoryListItem = React.memo(({ 
    item, 
    isSelected, 
    isSelectionMode, 
    onClick,
    onDelete 
}: { 
    item: HistoryItem, 
    isSelected: boolean, 
    isSelectionMode: boolean, 
    onClick: () => void,
    onDelete: (e: React.MouseEvent) => void
}) => {
    const dateStr = new Date(item.timestamp).toLocaleString('pt-BR', { 
        day: '2-digit', month: '2-digit', year: 'numeric', 
        hour: '2-digit', minute: '2-digit' 
    });

    const docTypeColors: Record<string, string> = {
        'Balanço Patrimonial': 'bg-blue-100 text-blue-700 border-blue-200',
        'DRE': 'bg-emerald-100 text-emerald-700 border-emerald-200',
        'Balancete': 'bg-purple-100 text-purple-700 border-purple-200',
        'Outro': 'bg-slate-100 text-slate-700 border-slate-200'
    };

    return (
        <div 
            onClick={onClick}
            className={`group relative p-4 rounded-xl border transition-all duration-200 cursor-pointer shadow-sm ${
                isSelected 
                ? 'border-blue-500 ring-2 ring-blue-500/20 bg-blue-50/30 dark:bg-blue-900/10' 
                : 'border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 hover:border-blue-300 dark:hover:border-slate-500'
            }`}
        >
            {isSelectionMode && (
                <div className={`absolute top-3 right-3 w-6 h-6 rounded-full border-2 flex items-center justify-center transition-colors ${
                    isSelected ? 'bg-blue-600 border-blue-600 shadow-lg shadow-blue-500/30' : 'border-slate-300 dark:border-slate-600'
                }`}>
                    {isSelected && <svg className="w-4 h-4 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>}
                </div>
            )}

            {!isSelectionMode && (
                <button 
                    onClick={onDelete}
                    className="absolute top-3 right-3 p-1.5 text-slate-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all rounded-md hover:bg-red-50 dark:hover:bg-red-900/20"
                    title="Excluir do histórico"
                >
                    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                </button>
            )}

            <div className="mb-3">
                <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full border uppercase tracking-wider ${docTypeColors[item.summary.document_type] || docTypeColors['Outro']}`}>
                    {item.summary.document_type}
                </span>
                <p className="font-bold text-slate-800 dark:text-white mt-1.5 leading-tight truncate pr-8" title={item.headerData.companyName}>
                    {item.headerData.companyName || 'Empresa não Identificada'}
                </p>
                <p className="text-[10px] text-slate-400 font-mono mt-0.5">{item.headerData.cnpj || 'CNPJ não inf.'}</p>
            </div>

            <div className="flex items-center justify-between text-[11px] text-slate-500 dark:text-slate-400">
                <div className="flex items-center gap-1.5">
                    <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                    {dateStr}
                </div>
                <div className="flex items-center gap-1.5 max-w-[100px] truncate">
                    <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" /></svg>
                    {item.headerData.collaboratorName || 'Sistema'}
                </div>
            </div>
        </div>
    );
});

const AnalysisHistory: React.FC<Props> = ({ 
    isOpen, 
    onClose, 
    history, 
    onSelect, 
    onClear, 
    onDeleteItem,
    onCompare,
    onConsolidate, 
    currentUser 
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'all' | 'mine'>('all');
  const [itemsToShow, setItemsToShow] = useState(ITEMS_PER_PAGE);
  const [isSelectionMode, setIsSelectionMode] = useState(false);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  useEffect(() => {
    if (!isOpen) {
        setIsSelectionMode(false);
        setSelectedIds([]);
        setSearchTerm('');
    }
  }, [isOpen]);

  const filteredHistory = useMemo(() => {
    let data = [...history];

    if (viewMode === 'mine' && currentUser) {
        data = data.filter(item => 
            item.headerData.collaboratorName?.toLowerCase().trim() === currentUser.toLowerCase().trim()
        );
    }

    if (searchTerm.trim()) {
        const s = searchTerm.toLowerCase();
        data = data.filter(item =>
          item.headerData.companyName?.toLowerCase().includes(s) ||
          item.fileName?.toLowerCase().includes(s) ||
          item.summary.document_type.toLowerCase().includes(s)
        );
    }
    return data;
  }, [history, searchTerm, viewMode, currentUser]);

  const displayedItems = filteredHistory.slice(0, itemsToShow);

  const toggleSelection = (id: string, docType: string) => {
      if (selectedIds.includes(id)) {
          setSelectedIds(prev => prev.filter(item => item !== id));
      } else {
          // Check consistency: Consolidation requires same DocType (ideally DRE)
          if (selectedIds.length > 0) {
              const firstItem = history.find(h => h.id === selectedIds[0]);
              if (firstItem && firstItem.summary.document_type !== docType) {
                  alert("Para comparar ou consolidar, selecione documentos do mesmo tipo (ex: Todos DRE).");
                  return;
              }
          }
          setSelectedIds(prev => [...prev, id]);
      }
  };

  const handleItemClick = (item: HistoryItem) => {
      if (isSelectionMode) {
          toggleSelection(item.id, item.summary.document_type);
      } else {
          onSelect(item);
      }
  };

  const handleAction = (action: 'compare' | 'consolidate') => {
      if (action === 'compare') {
          if (selectedIds.length !== 2) return;
          const i1 = history.find(h => h.id === selectedIds[0]);
          const i2 = history.find(h => h.id === selectedIds[1]);
          if (i1 && i2 && onCompare) {
              const sorted = [i1, i2].sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());
              onCompare(sorted[0], sorted[1]);
          }
      } else if (action === 'consolidate') {
          if (selectedIds.length < 2) return;
          const items = selectedIds.map(id => history.find(h => h.id === id)).filter(Boolean) as HistoryItem[];
          if (onConsolidate) onConsolidate(items);
      }
  };

  return (
    <div className={`fixed inset-0 z-50 transition-all duration-300 ${isOpen ? 'visible' : 'invisible'}`}>
      <div 
        className={`absolute inset-0 bg-slate-900/60 backdrop-blur-sm transition-opacity duration-300 ${isOpen ? 'opacity-100' : 'opacity-0'}`}
        onClick={onClose}
      />

      <div className={`absolute inset-y-0 right-0 max-w-md w-full bg-slate-50 dark:bg-slate-900 shadow-2xl flex flex-col transition-transform duration-300 ease-in-out ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}>

        {/* HEADER */}
        <div className="px-6 py-5 bg-white dark:bg-slate-800 border-b dark:border-slate-700 flex items-center justify-between">
          <div>
            <h2 className="text-xl font-bold text-slate-800 dark:text-white flex items-center gap-2">
                <svg className="w-5 h-5 text-blue-600" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                Histórico de Auditoria
            </h2>
            <p className="text-xs text-slate-500 dark:text-slate-400 mt-0.5">Gerencie e compare suas análises salvas</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-full transition-colors">
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        {/* SEARCH AND FILTERS */}
        <div className="p-4 bg-white dark:bg-slate-800 border-b dark:border-slate-700 space-y-4">
            <div className="relative">
                <input 
                    type="text" 
                    placeholder="Filtrar por empresa, tipo ou arquivo..." 
                    value={searchTerm} 
                    onChange={(e) => setSearchTerm(e.target.value)} 
                    className="w-full pl-10 pr-4 py-2 bg-slate-100 dark:bg-slate-900 border-transparent focus:bg-white dark:focus:bg-slate-800 focus:ring-2 focus:ring-blue-500 rounded-xl text-sm transition-all" 
                />
                <svg className="w-4 h-4 text-slate-400 absolute left-3.5 top-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
            </div>

            <div className="flex gap-2">
                <div className="flex bg-slate-100 dark:bg-slate-900 rounded-lg p-1 flex-1">
                    <button 
                        onClick={() => setViewMode('all')} 
                        className={`flex-1 py-1.5 text-xs font-bold rounded-md transition-all ${viewMode === 'all' ? 'bg-white dark:bg-slate-800 text-blue-600 shadow-sm' : 'text-slate-500'}`}
                    >
                        Todas
                    </button>
                    <button 
                        onClick={() => setViewMode('mine')} 
                        disabled={!currentUser}
                        className={`flex-1 py-1.5 text-xs font-bold rounded-md transition-all ${viewMode === 'mine' ? 'bg-white dark:bg-slate-800 text-blue-600 shadow-sm' : 'text-slate-500 disabled:opacity-40'}`}
                    >
                        Minhas
                    </button>
                </div>

                <button 
                    onClick={() => { setIsSelectionMode(!isSelectionMode); setSelectedIds([]); }}
                    className={`px-4 py-1.5 text-xs font-bold rounded-lg border transition-all ${
                        isSelectionMode ? 'bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-500/30' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-300'
                    }`}
                >
                    {isSelectionMode ? 'Cancelar Seleção' : 'Selecionar'}
                </button>
            </div>
        </div>

        {/* LIST */}
        <div className="flex-1 overflow-y-auto p-4 space-y-3">
          {filteredHistory.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-20 text-center px-6">
                <div className="w-16 h-16 bg-slate-100 dark:bg-slate-800 rounded-full flex items-center justify-center mb-4">
                    <svg className="w-8 h-8 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                </div>
                <h3 className="text-slate-800 dark:text-white font-bold">Nenhuma análise encontrada</h3>
                <p className="text-sm text-slate-500 mt-1">Realize uma nova análise para vê-la aqui ou altere seus filtros.</p>
            </div>
          ) : (
            <>
              {displayedItems.map((item) => (
                <HistoryListItem 
                    key={item.id} 
                    item={item} 
                    isSelected={selectedIds.includes(item.id)} 
                    isSelectionMode={isSelectionMode} 
                    onClick={() => handleItemClick(item)}
                    onDelete={(e) => {
                        e.stopPropagation();
                        if(confirm('Tem certeza que deseja excluir esta análise permanentemente?')) {
                            onDeleteItem?.(item.id);
                        }
                    }}
                />
              ))}

              {filteredHistory.length > itemsToShow && (
                <button 
                    onClick={() => setItemsToShow(prev => prev + ITEMS_PER_PAGE)}
                    className="w-full py-3 text-sm font-bold text-blue-600 hover:text-blue-700 hover:bg-blue-50 dark:hover:bg-blue-900/10 rounded-xl transition-all"
                >
                    Carregar mais registros
                </button>
              )}
            </>
          )}
        </div>

        {/* FOOTER ACTIONS */}
        <div className="p-4 bg-white dark:bg-slate-800 border-t dark:border-slate-700">
            {isSelectionMode ? (
                <div className="space-y-3">
                     <div className="grid grid-cols-2 gap-2">
                        <button 
                            onClick={() => handleAction('compare')}
                            disabled={selectedIds.length !== 2}
                            className={`py-3 px-2 rounded-xl font-bold text-xs shadow-lg transition-all border ${
                                selectedIds.length === 2 
                                ? 'bg-white text-blue-600 border-blue-200 hover:bg-blue-50' 
                                : 'bg-slate-100 text-slate-400 border-transparent cursor-not-allowed'
                            }`}
                        >
                            Comparar Horizontal (2)
                        </button>
                        <button 
                            onClick={() => handleAction('consolidate')}
                            disabled={selectedIds.length < 2}
                            className={`py-3 px-2 rounded-xl font-bold text-xs shadow-lg transition-all ${
                                selectedIds.length >= 2 
                                ? 'bg-purple-600 text-white hover:bg-purple-700 shadow-purple-500/20' 
                                : 'bg-slate-200 text-slate-400 cursor-not-allowed'
                            }`}
                        >
                            Aglutinar / Consolidar ({selectedIds.length})
                        </button>
                    </div>
                </div>
            ) : (
                <div className="flex gap-2">
                    <button 
                        onClick={onClear} 
                        className="flex-1 py-2.5 px-4 bg-red-50 dark:bg-red-900/10 text-red-600 border border-red-100 dark:border-red-900/30 hover:bg-red-100 rounded-xl text-xs font-bold transition-all"
                    >
                        Limpar Tudo
                    </button>
                    <button 
                        onClick={onClose} 
                        className="flex-1 py-2.5 px-4 bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-300 hover:bg-slate-200 rounded-xl text-xs font-bold transition-all"
                    >
                        Fechar
                    </button>
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

export default AnalysisHistory;

import React, { useState, useEffect, useMemo } from 'react';
import HeaderInputs from './components/HeaderInputs';
